/* ============================================================
   EON · knowledge/brain-qa.js  —  Eon's wide Q&A brain
   ------------------------------------------------------------
   A large offline question library (340 entries, ~1020+ question
   phrasings) covering academic life, productivity, data-science
   concepts, the Eon app itself, and small talk — so Eon answers
   practically far beyond the user's own records. Consulted AFTER
   the live data-grounded intents and the academic KB, BEFORE the
   creative fallback. Extend freely. Register: window.EonBrainQA.
   ============================================================ */

const QA = [
  { re: new RegExp("write (a |an |my )?sop|how (do i|to) (start|write).*statement of purpose|sop for (masters|phd|university)", "i"), a: ["Start with a specific moment that sparked your interest, not 'Since childhood I have been passionate.' Then connect your academics, projects, and goals to THIS program — admissions readers can smell a generic SOP instantly.", "Answer four questions in order: what do you want to study, why, what have you already done about it, and why this university. If a paragraph doesn't serve one of those, cut it.", "Write a messy first draft in one sitting, then revise five times. Bangladeshi applicants often over-formalize — plain, confident English beats flowery vocabulary every time. 😊"], d: ["• Hook: a concrete story or problem", "• Body: evidence — courses, research, work", "• Close: goals + fit with the program"] },
  { re: new RegExp("sop (structure|format|outline|length)|how long.*sop|sop word (count|limit)", "i"), a: ["A classic structure: hook (1 para), academic background (1-2), research/work experience (1-2), why this program (1), future goals (1). Aim for 800-1000 words unless the university specifies otherwise.", "Keep it to one page single-spaced if no limit is given. Every paragraph should end pointing toward the next — a good SOP reads like one continuous argument, not a stapled list.", "Follow the university's prompt religiously; if they ask 500 words, 501 signals you can't follow instructions. Structure matters less than a clear thread from past → present → future."] },
  { re: new RegExp("sop mistakes|what (not|to avoid).*sop|common.*sop (errors|problems)", "i"), a: ["Top killers: starting with 'Since my childhood,' listing your CV in prose, quoting Einstein, and praising the university with lines copied from its website. Be specific about yourself instead.", "Never reuse one SOP for every university with only the name swapped — readers notice, and one forgotten find-and-replace ('I dream of attending Oxford' sent to Cambridge) is fatal.", "Avoid explaining your whole life story. Admissions committees spend 5-10 minutes per file; make the first two sentences earn the rest of their attention."] },
  { re: new RegExp("personal statement vs sop|difference.*(sop|statement of purpose).*personal|what is a personal statement", "i"), a: ["An SOP is forward-looking and academic: what you'll study and why. A personal statement is backward-looking and human: who you are, what shaped you, what you overcame. Some schools blur the two — read the prompt.", "Rule of thumb: SOP = research goals and program fit; personal statement = your story, values, and resilience. Growing up in Bangladesh navigating load-shedding to study can belong in the second, not the first.", "If a school asks for both, don't repeat content. Split your material: achievements and plans in the SOP, character and motivation in the personal statement."] },
  { re: new RegExp("scholarship essay|essay for (a )?scholarship|winning.*scholarship (essay|application)", "i"), a: ["Scholarship essays are judged on impact and alignment: show measurable things you've done and connect them to the scholarship's mission. Chevening wants leaders, DAAD wants researchers, Fulbright wants cultural ambassadors.", "Use the STAR pattern for stories — Situation, Task, Action, Result — and always quantify results ('trained 40 students', 'raised ৳50,000'). Vague claims lose to concrete ones.", "Read the selection criteria and mirror their language. If they say 'community impact', your essay should contain a clear community-impact story, not just imply one."] },
  { re: new RegExp("research abstract|write (an )?abstract|abstract for (paper|thesis|conference)", "i"), a: ["A tight abstract has five moves in ~200 words: context, gap/problem, method, key result, implication. Write it LAST, after the paper, then trim every unnecessary word.", "One trick: write one sentence per section of your paper, stitch them together, then smooth. Avoid citations, abbreviations, and 'in this paper we will' padding.", "Lead with the problem, not the field. 'Dengue outbreaks in Dhaka are hard to predict' beats 'Machine learning has become increasingly popular in recent years.'"] },
  { re: new RegExp("fulbright|fullbright|fulbright (scholarship|application|bangladesh)", "i"), a: ["Fulbright for Bangladesh usually opens around February-May via the US Embassy Dhaka — it funds a US master's fully, and values leadership plus a clear plan to return and contribute to Bangladesh. That 'return home' commitment is central to your essays.", "You need a strong SOP, a personal statement, 3 recommendations, and later TOEFL/IELTS and sometimes GRE. Apply even without perfect scores first — shortlisted candidates take tests afterward in many cycles.", "Fulbright loves 'bridge builders': show how your field connects the US and Bangladesh. A community project or teaching experience often matters more than a perfect CGPA."], d: ["• Check: bd.usembassy.gov for the current cycle", "• 2-year home residency rule applies after", "• Emphasize service + return plans"] },
  { re: new RegExp("chevening|chevening (essay|scholarship|requirements)|uk government scholarship", "i"), a: ["Chevening funds a one-year UK master's and hinges on four essays: leadership, networking, why-UK study plan, and career plan. You need 2+ years of work experience (2,800 hours) — internships and part-time count.", "Applications open in August, close early November. The essays reward specificity: name real people you led, real outcomes, and real UK courses — up to three course choices, so research them properly.", "Chevening explicitly wants future leaders who'll return home for 2 years. Frame everything around the change you'll drive in Bangladesh after your UK degree."] },
  { re: new RegExp("erasmus mundus|erasmus (scholarship|masters)|emjmd|em(jm)?d program", "i"), a: ["Erasmus Mundus Joint Masters let you study in 2-3 European countries on one full scholarship (~€1,400/month plus tuition and travel). Each program applies separately, usually October-January, so shortlist 3+ programs from the official EMJM catalogue.", "No application fee for most, IELTS around 6.5, and your motivation letter + CV carry huge weight since there's rarely an interview. Tailor each letter to that consortium's specific universities.", "It's one of the friendliest options for Bangladeshi students: no bank statement stress, no GRE for most programs, and the multi-country experience is genuinely fun. 🌍"] },
  { re: new RegExp("study in germany.*scholarship|german(y)? scholarship", "i"), a: ["DAAD's flagship for us is the EPOS/development-related master's scholarships: full funding plus ~€992/month, but most require 2 years of relevant work experience after your bachelor's. Deadlines vary per program, often August-October.", "Germany's real secret: most public universities charge no tuition anyway, so even without DAAD you can study for semester fees of ~€300. You'd need a blocked account (~€11,900/year) for the visa though.", "For research-focused applicants, look at DAAD research grants and write to German professors first — a professor's acceptance letter dramatically strengthens your application."] },
  { re: new RegExp("commonwealth scholarship|csc uk|commonwealth (masters|phd|shared)", "i"), a: ["Commonwealth Scholarships fund full UK master's/PhD study for citizens of Commonwealth countries — Bangladesh qualifies. Master's applications typically run September-October via the CSC portal, often needing nomination through the UGC in Bangladesh.", "They prioritize development impact: your study plan should map to themes like health, technology, or climate resilience in Bangladesh. Write your essays around one of their six development themes.", "Also check Commonwealth Shared Scholarships (applied via specific UK universities) and Split-site PhD options — many applicants miss these lower-competition routes."] },
  { re: new RegExp("japan(ese)? government scholarship|study in japan.*scholarship", "i"), a: ["MEXT (embassy track) opens around April-May at the Japanese Embassy in Dhaka: full tuition, monthly stipend (~¥144,000 for research students), and airfare. It involves a written exam (English, and math/science for undergrad track) plus an interview.", "For the research (graduate) track, contacting a Japanese professor and getting an informal acceptance before or during screening is a big advantage — your field-of-study plan is the heart of the application.", "No IELTS is strictly required for embassy MEXT, and Japanese language isn't mandatory for many graduate programs, though learning basic Japanese helps daily life a lot."] },
  { re: new RegExp("gks|kgsp|korea(n)? (government )?scholarship|study in (south )?korea", "i"), a: ["GKS (formerly KGSP) fully funds study in Korea including a year of Korean language training, tuition, and ~1 million won/month. Two tracks: Embassy (apply via Korean Embassy Dhaka, ~February for grad) and University (apply directly, more seats for some schools).", "You can't apply to both tracks in the same cycle — Embassy lets you pick 3 universities, University track just one. Research which universities historically take Bangladeshi students in your field.", "A TOPIK (Korean) certificate isn't required but level 3+ gives bonus points and can skip the language year. Grades matter: you generally need 80%+ or top-20% standing."] },
  { re: new RegExp("turkiye burslari|turkish scholarship|study in turkey", "i"), a: ["Türkiye Bursları covers tuition, dorm, insurance, flights, and a monthly stipend, plus a year of Turkish language study. Applications open roughly January-February each year on turkiyeburslari.gov.tr — completely free to apply.", "Undergrad applicants need 70%+ grades (90%+ for medicine); it's very competitive, so your letter of intent and documented extracurriculars are what separate you. Interviews happen at the embassy or online.", "Note you'll study in Turkish for many programs (English options exist, especially at grad level) — check each university's medium of instruction before ranking your choices."] },
  { re: new RegExp("indian? (government )?scholarship|study in india.*scholarship", "i"), a: ["ICCR scholarships fund Bangladeshi students for bachelor's/master's/PhD in India — tuition, hostel, and a monthly stipend. Applications go through the A2A portal (a2ascholarships.iccr.gov.in), usually opening around February-April.", "You choose up to 5 institutions and must pass an English proficiency test conducted by the High Commission if required. Engineering, science, and humanities all have seats; medicine (MBBS) is excluded.", "It's a solid low-cost option close to home — living costs are manageable and the stipend covers basics, though budget some personal funds (₹/৳) for comfort."] },
  { re: new RegExp("ielts prep|prepare.*ielts|how.*study.*ielts|ielts in \\d+ (weeks|months|days)", "i"), a: ["Take a full mock test first to find your baseline, then drill your weakest module daily. Cambridge IELTS books 10-19 are the gold standard — do them under strict timing.", "A realistic plan: 6-8 weeks, 1.5-2 hours daily. Listening and Reading improve fast with practice; Writing and Speaking need feedback, so get a teacher, a study partner, or record yourself.", "Free resources go far: IELTS Liz and IELTS Advantage for writing, BBC/podcasts for listening, and one Cambridge test per week as a checkpoint. Consistency beats cramming."] },
  { re: new RegExp("ielts writing (band|7|score)|improve.*ielts writing|task 2 (essay|writing)", "i"), a: ["Band 7 writing is about task response and structure, not fancy words. Answer every part of the question, one clear idea per body paragraph, and a real position stated in the intro and conclusion.", "Most Bangladeshi candidates get stuck at 6.5 from memorized templates and overused linkers ('moreover, furthermore'). Examiners penalize that — use natural connections and specific examples instead.", "Get your essays checked against the public band descriptors. Fixing grammar range (complex sentences used correctly) and task response usually adds the half-band you need."] },
  { re: new RegExp("ielts speaking|speaking (band|score|test) (tips|improve)|cue card", "i"), a: ["Speak in ideas, not memorized answers — examiners detect scripts and dock you. Fluency with small mistakes beats slow, perfect sentences.", "For Part 2 cue cards, use a simple frame: what, when/where, who, how you felt, why it matters. Practice speaking for the full 2 minutes daily with a phone timer.", "Record yourself answering past Part 3 questions, then listen for fillers and flat intonation. Shadowing English podcasts 15 minutes a day noticeably smooths pronunciation in a month."] },
  { re: new RegExp("toefl (or|vs) ielts|ielts (or|vs) toefl|which.*(english test|toefl|ielts).*better", "i"), a: ["Both are accepted almost everywhere now. Choose IELTS if you prefer paper options, a human speaking interview, and UK/Australia focus; choose TOEFL if you're comfortable typing fast and doing everything on a computer — it's slightly more US-flavored.", "Cost in Bangladesh is similar (around ৳22,000-28,000 depending on the test and year). Take a free practice test of each and pick whichever format felt easier — the score difference for most people is small.", "Check your target universities first: a few UK visa routes prefer IELTS (UKVI version), and some US programs list TOEFL sub-score minimums. The requirement sheet decides, not general opinion."] },
  { re: new RegExp("gre prep|prepare.*gre|gre (study plan|quant|verbal|score)", "i"), a: ["The shortened GRE is under 2 hours now. Plan 2-3 months: ETS Official Guide + PowerPrep mocks are essential; add Gregmat or Magoosh for structure and Manhattan 5lb for quant drills.", "Bangladeshi STEM students usually find quant friendly (165+ is realistic with practice) but verbal is the grind — learn vocabulary in context through reading, not just word lists.", "Take both free PowerPrep tests under real conditions; your target should be the average admitted score of your dream programs, not a universal number. Many programs are GRE-optional now, so verify before spending ৳26,000+."] },
  { re: new RegExp("(is|do i need).*gre|gre (required|optional|waiver)|apply without gre", "i"), a: ["Post-2020, a large share of US programs are GRE-optional or GRE-blind — check each department's admissions page for the current cycle, as policies flip year to year.", "If you're optional-eligible: submit a GRE only if it strengthens you (roughly 315+ for most programs, higher for top CS/engineering). A weak score can hurt more than no score.", "For funded PhD/MS applications with a modest CGPA, a strong GRE can offset it — that's the main case where taking it is clearly worth the money and time."] },
  { re: new RegExp("sat prep|prepare.*sat|sat (score|exam|for us universities)|digital sat", "i"), a: ["The Digital SAT is adaptive and ~2h14m. The official prep is genuinely the best: Bluebook app mocks plus Khan Academy's free course — do all six official practice tests before test day.", "For US undergrad with aid, aim 1450+ to be competitive at generous need-based schools; but note many universities are test-optional, so a strong SAT is a weapon, not always a requirement.", "Registration from Bangladesh runs about $68 + international fee — book early since Dhaka test centers fill fast. Fee waivers generally aren't available to international students, so budget for 1-2 attempts."] },
  { re: new RegExp("duolingo (english )?test|det (score|accepted)|cheaper.*english test", "i"), a: ["The Duolingo English Test costs about $65, is taken from home in an hour, and results come in ~2 days — a genuine budget saver versus IELTS. Thousands of universities accept it, mostly in the US and Canada.", "Caution: many UK visa routes, Australian visas, and some scholarship bodies still require IELTS/TOEFL. Verify both the university AND the visa/scholarship accept DET before relying on it.", "A DET 120 roughly maps to IELTS 6.5-7.0. Practice the question types on their official site — the adaptive format and strict camera rules trip people up more than the English does."] },
  { re: new RegExp("what ielts score.*need|minimum ielts|ielts (requirement|band) for (usa|uk|canada|australia|germany)", "i"), a: ["Typical floors: US/Canada grad programs 6.5-7.0 (writing 6.0+), UK master's 6.5, Australia 6.5 with 6.0 in each band, German English-taught programs 6.5. Top programs and scholarships often want 7.0+.", "Sub-scores matter as much as the overall — a 7.0 overall with 5.5 writing fails many requirements. Check each band minimum on the program page.", "If you're 0.5 short, some universities offer conditional admission with a pre-sessional English course, and a few accept MOI letters instead — ask the admissions office directly before retaking."] },
  { re: new RegExp("which country.*study|choose.*country.*(study|abroad)|best country for (bangladeshi|international) students", "i"), a: ["Match the country to your constraint: fully-funded need → US PhDs, Erasmus, MEXT, GKS; low tuition with self-funding → Germany; fast one-year degree → UK; immigration pathway → Canada/Australia; research + stipend without IELTS stress → Japan/Korea.", "Don't choose by Facebook group hype. List your top 3 priorities (funding, PR prospects, research quality, family) and score each country against them — the answer usually becomes obvious.", "Also weigh total cost honestly in taka: a 'cheap' country with no work rights can cost more than an expensive one with assistantships. Funding structure beats sticker price."] },
  { re: new RegExp("study in (the )?(usa|us|america|united states)|us(a)? (admission|universit|grad school)", "i"), a: ["The US route: strong profile + SOP + 3 recommendations, applications due Dec-Jan for Fall, and funding via assistantships (common for PhD, possible for MS). Application fees run $75-125 each, so shortlist strategically.", "For funded study, PhD programs are the sweet spot — tuition waiver plus ~$2,000+/month stipend is standard. Direct PhD after a bachelor's is normal in the US, unlike Europe.", "Undergrad with aid is harder but real: a handful of need-blind or need-generous colleges (think liberal arts colleges) fund international students — strong SAT, essays, and extracurriculars are the currency."] },
  { re: new RegExp("study in (the )?uk|uk (masters|admission|universit)|one year masters", "i"), a: ["UK master's are one year — cheaper in time, but tuition runs £15,000-35,000 and scholarships (Chevening, Commonwealth, GREAT, university awards) are competitive. Apply from September onward; many programs are rolling.", "The Graduate Route visa gives 2 years of post-study work rights (18 months for some newer rules — verify current policy), which matters for recovering costs.", "No GRE needed, personal statement carries big weight, and offers can be conditional on IELTS — you can often apply first and test later. Budget the ~£1,483/month (London) maintenance funds for the visa."] },
  { re: new RegExp("study in germany|german univers|tuition free (europe|germany)", "i"), a: ["Germany's public universities charge little to no tuition even for internationals — you pay a semester fee (~€150-350) that often includes transport. English-taught master's are plentiful; use the DAAD database to find them.", "The catch is the blocked account: roughly €11,900 for the visa, about ৳15-16 lakh shown upfront. Students can work 140 full days a year to offset living costs.", "Winter intake deadlines are typically March-July via uni-assist or direct portals. German isn't required for English programs, but A2-B1 German transforms your job prospects after graduation."] },
  { re: new RegExp("study in japan|japan(ese)? univers|research student japan", "i"), a: ["Japan's main doors: MEXT (embassy or university track), the 'research student' route where a professor accepts you before formal enrollment, and English-taught programs like those at Tokyo, Kyoto, Tohoku, and Tsukuba.", "Emailing professors matters enormously in Japan — a supervisor's informal consent often precedes admission. Write short, specific emails referencing their actual papers.", "JASSO and university scholarships supplement MEXT, and part-time work (up to 28h/week) is permitted. Japanese language isn't required for many grad programs but makes life far richer."] },
  { re: new RegExp("study in (south )?korea(?! town)|korean univers|snu|kaist|yonsei|postech", "i"), a: ["Beyond GKS, Korean universities themselves fund heavily: KAIST and POSTECH often cover full tuition plus stipend for grad students, and SNU/Yonsei/Korea University have generous merit awards for internationals.", "Grad admission usually needs a professor's lab to accept you — email professors with your CV and a short research pitch before applying. Spring (March) and Fall (September) intakes both exist.", "English suffices academically in STEM labs, but daily life runs on Korean; the GKS language year or self-study to TOPIK 2-3 pays off in friendships and part-time work."] },
  { re: new RegExp("study in australia|australian? (univers|visa|scholarship)|subclass 500", "i"), a: ["Australia offers Australia Awards (fully funded, development-focused — Bangladesh is eligible), Research Training Program stipends for research degrees, and university merit scholarships. Coursework master's are mostly self-funded at AUD 35,000-50,000/year.", "The subclass 500 visa wants Genuine Student evidence and proof of funds; IELTS 6.5 (no band under 6.0) is the common academic bar. Post-study work rights of 2-4 years follow most degrees.", "Living costs are high, but 48 hours/fortnight of permitted work at ~AUD 24+/hour helps meaningfully — just never let work sink your grades, since visa renewals watch progress."] },
  { re: new RegExp("study in canada|canadian? (univers|college|admission)|sds canada", "i"), a: ["Canada's appeal is the pathway: study permit → Post-Graduation Work Permit → PR points. Funding-wise, thesis-based master's and PhDs often come with supervisor funding; coursework programs are mostly self-funded at CAD 20,000-40,000/year.", "You now need a Provincial Attestation Letter and roughly CAD 20,635+ in proof of funds beyond tuition. Rules have tightened recently, so check IRCC's current requirements rather than older Facebook posts.", "For funded spots, email potential supervisors at schools like Toronto, UBC, Waterloo, and Memorial — a professor saying 'I'll fund this student' is the strongest card in Canadian grad admissions."] },
  { re: new RegExp("shortlist.*universit|choose.*universit|how many universit.*apply|safety.*reach.*school", "i"), a: ["Build a ladder: 2-3 reach, 3-4 match, 2 safe — judged by admitted-student profiles, not rankings alone. For funded grad study, 'match' means professors there actually work on your topic.", "Filter in this order: does it have your exact research area → funding availability → admission stats → location/cost. Rankings come last; a well-funded #150 beats an unfunded #40.", "Make a spreadsheet with deadlines, fees, test requirements, and one professor of interest per school. Application fees add up (often $75-125 each, ৳9,000-15,000), so 8-10 well-chosen schools beats 20 random ones."] },
  { re: new RegExp("email (a |to )?professor|cold email.*(professor|supervisor)|contact.*professor.*research", "i"), a: ["Keep it under 150 words: who you are (1 line), which of THEIR papers interested you and why (2-3 lines), your relevant skill or result (1-2 lines), and a clear ask — 'Are you accepting students for Fall 2027?' Attach your CV.", "Subject line does half the work: 'Prospective PhD student — [topic] — Fall 2027' beats 'Request for supervision.' Never mass-email; a mismatched topic email gets deleted and remembered.", "Read at least the abstract and conclusion of one recent paper and say something specific about it. Professors reply to genuine engagement, not flattery about being 'esteemed.'"], d: ["• Send Tue-Thu, their morning time", "• One professor per department at a time", "• Proofread the name — twice"] },
  { re: new RegExp("professor (didn'?t|not|hasn'?t) repl|follow up.*professor|no reply.*(professor|email)", "i"), a: ["Silence is normal, not rejection — professors drown in email. Send one polite follow-up after 10-14 days: reply to your original thread with two lines, don't start fresh.", "After one follow-up with no answer, move on gracefully. A non-reply costs you nothing; there are many professors, and admission committees often matter more than one individual anyway.", "Improve your hit rate: check if they posted 'not accepting students' on their website, email early in the semester rather than during grant deadlines, and make your ask answerable in one sentence."] },
  { re: new RegExp("research proposal|write.*proposal.*(phd|research|masters)|proposal (structure|format)", "i"), a: ["A solid proposal (1,500-3,000 words unless specified): background and gap, research questions, methodology, expected contribution, rough timeline, and key references. The gap is the heart — show what's missing that YOU will fill.", "Make questions answerable within the degree's timeframe. 'Solve dengue prediction' is a career; 'evaluate three forecasting models on Dhaka's 2015-2024 dengue data' is a thesis.", "Align it with your target supervisor's work — cite them where honest. Proposals are judged on feasibility and clarity, not ambition; a modest, sharply-defined plan wins."] },
  { re: new RegExp("thesis writing|write (my )?thesis|dissertation (tips|help|writing)", "i"), a: ["Write daily in small blocks — 300 words a day finishes a chapter a month. Start with methodology and results (easiest to draft), leave introduction and abstract for last.", "Keep a reference manager (Zotero is free) from day one; retro-fitting 80 citations at the end is misery. And back up to cloud after every session — thesis-on-a-dead-laptop stories are tragically common.", "Meet your supervisor with specific questions and a written agenda, and send drafts chapter by chapter rather than a 100-page surprise. Feedback loops are what actually improve a thesis."] },
  { re: new RegExp("thesis topic|choose.*(thesis|research) topic|(find|pick).*research (topic|idea)", "i"), a: ["Pick the intersection of three circles: what interests you, what your supervisor can actually guide, and what data/equipment you can access in Bangladesh. Missing any one of those makes for a painful year.", "Read the 'future work' sections of 5 recent papers in an area you like — they're literally lists of thesis topics the field wants answered.", "Prefer a small question you can answer completely over a grand one you can only wave at. Examiners reward depth and rigor, not scope."] },
  { re: new RegExp("plagiaris|avoid plagiarism|turnitin|similarity (score|index|report)", "i"), a: ["Plagiarism includes paraphrasing without citation and reusing your own submitted work — not just copy-paste. When in doubt, cite; over-citation is never punished, under-citation can end degrees.", "For Turnitin, similarity under ~15-20% is typically fine if matches are references and common phrases. What matters is whether uncited text matches sources — read the report, don't just chase the number.", "Safest workflow: read the source, close it, write from memory in your own words, then cite. Never keep the source open while 'paraphrasing' — that's how accidental plagiarism happens."] },
  { re: new RegExp("citation (style|format)|apa|ieee|harvard referencing|how to (cite|reference)|paraphras(e|ing) properly", "i"), a: ["Use whatever style your department mandates — IEEE for engineering, APA for social sciences, Harvard commonly in UK-style programs — and be ruthlessly consistent. A reference manager like Zotero or Mendeley formats it automatically.", "Good paraphrasing changes structure AND wording while keeping the idea, and still ends with a citation. Swapping synonyms in the same sentence structure is still plagiarism.", "Quote directly only when exact wording matters (definitions, famous claims); otherwise paraphrase. And cite the source you actually read, not one you saw cited elsewhere."] },
  { re: new RegExp("low (cgpa|gpa)|gpa (too low|3\\.[0-4]|below)|bad grades.*(apply|scholarship|abroad)", "i"), a: ["A low CGPA isn't fatal — admissions look at trajectory, research, and test scores too. An upward trend in later semesters, a strong GRE, publications, or solid work experience can each rebalance the file.", "Address it briefly and factually if there's a real reason (illness, family crisis, working to support family) — one or two sentences in the SOP or an optional addendum, framed around what changed after.", "Target realistically: funded PhDs care most about research fit, and some excellent programs weigh the last two years more heavily. Ask departments directly about minimums — many say 3.0 but flex for strong research profiles."] },
  { re: new RegExp("cgpa convers|transcript (evaluation|attest|wes)|4 scale.*gpa|gpa out of 5", "i"), a: ["Don't self-convert your CGPA on applications — report it as issued (e.g., 3.75/4.00 from your university) and let the university evaluate. If they require conversion, WES or ECE evaluation costs roughly $100-230 plus courier.", "For Bangladeshi transcripts: request several sealed sets from your registrar early — issuing can take weeks, and some universities want them mailed directly. Scan clean copies for online uploads.", "SSC/HSC GPA-5 scale students applying for undergrad: most US/UK systems understand it, but include the grading-scale explanation your board or school provides. Attestation from the education board/ministry may be needed for some countries."] },
  { re: new RegExp("study gap|explain.*gap year|gap.*(after|between).*(hsc|graduation|degree)", "i"), a: ["Gaps are only a problem when unexplained. One honest sentence — 'I spent 2024 preparing for admissions while working at X / caring for family / building Y project' — resolves most concerns.", "Fill current or future gaps with anything documentable: online courses with certificates, freelance work, volunteering, language prep. Visa officers and universities both prefer evidence over apology.", "Country notes: most grad programs don't mind gaps of 1-3 years at all, especially with work experience. For undergrad, gaps beyond 2 years get more scrutiny — a short explanation letter usually suffices."] },
  { re: new RegExp("tuition (cost|fees)|afford.*study abroad|total cost.*(usa|uk|canada|abroad)|funding options", "i"), a: ["Rough all-in yearly costs: US $40-80k unfunded, UK £25-45k, Canada CAD 35-55k, Australia AUD 45-65k, Germany €12-15k (living only), Japan/Korea often near-zero with scholarships. Funding strategy matters more than destination dreams.", "Stack funding sources: external scholarships + university awards + assistantships + permitted part-time work. Very few people pay sticker price; the skill is applying to programs structured to fund people like you.", "If family funds are limited (say under ৳20-30 lakh total), aim at fully-funded routes first — US PhDs, Erasmus Mundus, MEXT, GKS, DAAD, Commonwealth — rather than loans for self-funded master's."] },
  { re: new RegExp("fully funded|full(y)? scholarship list|scholarship.*without ielts|free study abroad", "i"), a: ["The big fully-funded family for Bangladeshis: Fulbright (US), Chevening & Commonwealth (UK), Erasmus Mundus (EU), DAAD (Germany), MEXT (Japan), GKS (Korea), Türkiye Bursları, ICCR (India), Australia Awards, and Chinese CSC. Each has different deadlines, so build a 12-month calendar.", "'Without IELTS' usually means MOI-accepted or embassy-tested options: MEXT, some GKS universities, Türkiye Bursları, ICCR, and many Chinese CSC programs. Don't pay any 'agent' for these — all are free to apply.", "Apply to 3-5 in one cycle with tailored essays rather than 15 with one recycled essay. These are essay-and-interview games; depth beats volume."], d: ["• Aug-Nov: Chevening, DAAD, Commonwealth, Erasmus", "• Jan-Apr: Türkiye, GKS, ICCR, MEXT", "• All official portals are free"] },
  { re: new RegExp("assistantship|ta ?ship|ra ?ship|teaching assistant.*fund|research assistant.*(stipend|fund)", "i"), a: ["In the US, assistantships are the main funding engine: TAs teach/grade, RAs work on a professor's grant — both typically waive tuition and pay a living stipend. PhD students get them almost by default; MS students should ask departments directly about availability.", "To land an RA, your email to professors should highlight skills that save them time: specific tools, lab techniques, or a relevant project. Funding follows usefulness.", "TA-ship tip: strong English speaking scores help (some universities require a speaking sub-score like TOEFL Speaking 23+ or a SPEAK test for TAs), so keep that in mind when testing."] },
  { re: new RegExp("erasmus\\+? exchange|semester exchange|student exchange program|credit mobility", "i"), a: ["Erasmus+ ICM (credit mobility) lets students at partner Bangladeshi universities spend a funded semester in Europe — grants around €800-900/month plus travel. Ask your university's international office which European partnerships exist; these go criminally under-used.", "Exchanges are also a strategic play: a European semester on your transcript plus professors who can recommend you makes later master's applications much stronger.", "Beyond Erasmus, look at Japan's JASSO exchanges, South Korea's university partnerships, and programs like Global UGRAD (US, fully funded semester for undergrads via the US Embassy)."] },
  { re: new RegExp("summer (school|program|research)|research internship abroad|mitacs|daad wise|utrip", "i"), a: ["Funded summer research programs open to Bangladeshi undergrads include Mitacs Globalink (Canada, apply ~September), UTRIP (University of Tokyo), Caltech SURF variants, EPFL Excellence, and several Max Planck/DAAD-linked internships in Germany.", "These typically want a 3.7+/4.0 CGPA, one or two strong recommendations, and a focused motivation letter. Apply 8-10 months before the summer — most deadlines land September-January.", "A funded summer abroad is the single best CV item for later PhD applications: it yields an international recommendation letter, research output, and proof you can work in a foreign lab."] },
  { re: new RegExp("olympiad|(math|physics|informatics|biology) olympiad|imo|ipho|ioi.*prep", "i"), a: ["Bangladesh's pipelines are well-organized: BdMO for math, BdPhO for physics, BdOI for informatics, biology and chemistry olympiads too — regional rounds lead to national camps and international teams. Start with past national problems, freely available online.", "For math, work through Art of Problem Solving books and prior BdMO/IMO shortlists; for informatics, grind Codeforces and USACO training. Consistent problem-solving hours matter more than talent mythology.", "Even without a medal, olympiad participation signals rigor on university applications — document your rounds, ranks, and camps. And the community you meet there is half the value. 🏅"] },
  { re: new RegExp("science (fair|project)|isef|regeneron|science project idea", "i"), a: ["Pick a problem you can measure locally — water quality, air pollution, crop disease, traffic — over an impressive-sounding one you can't test. Judges reward a real experiment with controls over a flashy demo.", "Follow the actual scientific method visibly: hypothesis, method, data, limitations. A logbook with dated entries impresses judges enormously and doubles as your report skeleton.", "In Bangladesh, national fairs and events run through schools, BFF (Bangladesh Freedom Foundation) grants, and university-hosted fairs; strong projects can route toward ISEF affiliation. Ask your science teacher who coordinates it in your district."] },
  { re: new RegExp("\\bmun\\b|model united nations|mun (prep|position paper|award)", "i"), a: ["MUN success is 70% preparation: know your country's real foreign policy on the agenda, write a tight position paper, and come with 2-3 draft clauses ready. Confidence in moderated caucuses grows from having something concrete to propose.", "Speak early — the first sessions set who committee members treat as a leader. Short, structured speeches (problem, position, proposal) beat long eloquent ones.", "For applications later, MUN counts most when you show progression: delegate → award winner → chair/organizer. Organizing a conference is a genuine leadership credential."] },
  { re: new RegExp("debate (tips|club|competition)|british parliamentary|improve.*debat", "i"), a: ["Structure wins debates: signpost your case (we argue X for reasons A, B), give mechanism + example for each argument, and spend real time on rebuttal — judges score clash, not parallel speeches.", "Practice matters more than English polish. Join your institution's club, do 2-3 practice rounds a week, and record speeches to catch pace and filler words.", "In BP format, extensions and whip speeches are where rounds are won — study how top speakers summarize clash. YouTube finals of WUDC and Asian championships are free masterclasses."] },
  { re: new RegExp("extracurricular|ecas? for (universit|scholarship)|build (my )?profile|spike vs well.rounded", "i"), a: ["Depth beats breadth: two activities with leadership and measurable outcomes outshine ten memberships. Admissions folks call it a 'spike' — become known for one thing.", "Choose activities that generate evidence: founded something, taught someone, published, won, organized. 'Member of X club' is filler; 'trained 30 juniors who then won Y' is a story.", "Start from what you'd do anyway and add structure to it. Passion sustained for two years reads as authentic; a sudden pre-application activity burst reads as exactly what it is."] },
  { re: new RegExp("publish.*(undergrad|paper|student)|first (research )?paper|how.*get published", "i"), a: ["The realistic undergrad path: join a professor's ongoing work rather than starting solo. Offer to handle literature review, data collection, or coding — co-authorship follows contribution.", "Start smaller than a Q1 journal: national conferences, IEEE regional conferences, or workshop papers are legitimate first steps and teach you the peer-review dance with lower stakes.", "Beware predatory journals that email you promising publication in days for a fee — a predatory publication actively damages applications. Check the venue on Scopus/DOAJ or ask a faculty member first."] },
  { re: new RegExp("journal (or|vs) conference|where.*(submit|publish).*paper|choose.*(journal|venue)", "i"), a: ["In CS/engineering, good conferences (peer-reviewed, indexed) carry real weight and decide faster; in most other sciences, journals dominate. Ask what your specific field's respected venues are — your supervisor's own publication list is the map.", "Match ambition to the work: a solid class project fits a regional conference or workshop; novel results with strong evaluation can aim at indexed journals. Rejection with reviews is still progress — revise and resubmit.", "Check indexing (Scopus, Web of Science, or DBLP for CS) and realistic acceptance timelines. For grad applications with deadlines, a conference's 3-month cycle may serve you better than a journal's 12."] },
  { re: new RegExp("who.*(ask|choose).*recommend|recommendation letter.*(who|choose)|referee.*(choose|select)", "i"), a: ["Choose people who know your work closely over people with big titles who barely know you. A detailed letter from your thesis supervisor beats a generic one from a department chair every time.", "Ideal mix for grad school: two academic (course teacher who saw you excel, research supervisor) and one professional if relevant. For scholarships like Chevening, a leadership-context referee helps.", "Ask early — a month minimum — and ask directly: 'Would you be able to write me a strong letter?' The word 'strong' gives them a graceful exit if they can't, which protects you."] },
  { re: new RegExp("draft.*(my own )?recommendation|professor (asked|told).*write.*letter|lor (sample|draft|content)", "i"), a: ["If a recommender asks you to draft it (common in Bangladesh), write in their voice about specific incidents: the question you asked in class, the problem you solved, how you compared to peers. Specifics make letters credible.", "Give each recommender a 'brag sheet': your CV, the programs and deadlines, what each program values, and 2-3 stories they witnessed. Even professors writing their own letters produce better ones with this.", "Vary the letters if you're drafting multiple — identical phrasing across letters gets flagged. Different recommenders should emphasize different strengths: one academic rigor, one research, one character/leadership."] },
  { re: new RegExp("application timeline|when.*deadline.*(fall|spring)|apply.*fall 20\\d\\d|admission calendar", "i"), a: ["For US Fall intake: tests done by September, professor emails August-October, applications December-January, decisions February-April, visa May-July. Working backward, serious prep starts 12-15 months before you'd fly.", "UK/Australia are more forgiving with rolling admissions — you can apply 6-9 months out — but scholarship deadlines (Chevening in November, Commonwealth in autumn) still force early action.", "Make one spreadsheet with every deadline, then set personal deadlines two weeks earlier. Recommenders, transcripts, and test reporting all take longer than you expect — buffer is everything."] },
  { re: new RegExp("when.*start prepar|how early.*(apply|prepare)|(1st|2nd|3rd|first|second|third) year.*prepare", "i"), a: ["Ideal arc from 2nd year of undergrad: build CGPA and one deep extracurricular; 3rd year: research involvement + start test prep; final year: tests done, professor outreach, applications. But late starters succeed constantly — compress, don't despair.", "If you're graduating soon and starting from zero, a gap year used well (IELTS/GRE, research assistantship at your own university, a publication attempt) often produces a stronger application than a rushed one.", "The single highest-leverage early move: get into a research group at your university now. Everything else — letters, SOP material, publications — flows from that."] },
  { re: new RegExp("f1 visa|us (student )?visa interview|visa interview.*(question|tips|dhaka)", "i"), a: ["The F1 interview at Dhaka is short — often 2-4 minutes. Officers probe three things: are you a genuine student (know your program and why this university), can you pay (know your funding source precisely), and will you comply with visa terms. Answer directly, no memorized speeches.", "Know your numbers cold: total cost, who's paying, sponsor's occupation, scholarship/assistantship amounts. Hesitation on funding is the most common refusal trigger.", "Bring documents organized but expect them to ask for none. Speak English confidently, keep answers to 1-2 sentences, and if refused under 214(b), you can reapply once something material changes."] },
  { re: new RegExp("uk (student )?visa|cas (letter|statement)|tier 4|student route visa", "i"), a: ["UK Student visa needs your CAS from the university, proof of maintenance funds (tuition balance plus £1,483/month for London or £1,136 outside, held 28 consecutive days), TB test certificate from an approved Dhaka clinic, and the IHS surcharge payment.", "The 28-day rule catches many people: the money must sit untouched in an acceptable account for 28 days ending within 31 days of application. Move funds early and don't dip below the line.", "Credibility interviews happen for some applicants — be ready to explain your course choice and career plan naturally. Agents can't attend that for you, so own your story."] },
  { re: new RegExp("bank (statement|solvency)|proof of funds|sponsor.*(visa|financial)|financial document.*(visa|admission)", "i"), a: ["General rule: show liquid funds (savings/FDR) covering first-year costs, in your or your sponsor's (usually parent's) account, with a sponsorship letter and evidence of income source. Property papers support the story but rarely count as primary funds.", "Sudden large deposits raise questions everywhere — season the funds and keep documentation of where money came from (sale deed, business income, remittance records).", "Each country differs: US wants funds matching the I-20 amount, UK enforces the 28-day rule, Germany uses a blocked account, Canada now expects CAD 20,635+ plus first-year tuition. Follow the checklist for YOUR route, not generic advice."] },
  { re: new RegExp("fee waiver|application fee.*(waive|too expensive)|apply.*free.*universit", "i"), a: ["Many US programs waive fees if you email the graduate coordinator explaining financial hardship as an international applicant — a polite two-line request works surprisingly often. Some waive automatically for McNair-equivalent or diversity fairs attendees.", "Zero-fee options exist across whole systems: most German universities, many Erasmus Mundus programs, several Canadian and Nordic schools, and essentially all the government scholarships (MEXT, GKS, Türkiye) cost nothing to apply.", "Attend virtual grad fairs and info sessions — universities frequently hand out fee-waiver codes to attendees. Thirty minutes on Zoom can save you $100 (over ৳12,000) per application."] },
  { re: new RegExp("academic cv|cv for (scholarship|grad school|phd|masters)|resume vs cv", "i"), a: ["An academic CV leads with education, then research experience, publications, awards, skills, and activities — no photo, no personal details like father's name or religion, which are common on Bangladeshi CVs but wrong for international applications.", "Use bullet points with verbs and numbers: 'Analyzed 3 years of hospital data using Python, presented at X conference.' One to two pages for early-career applicants.", "Tailor per purpose: for research programs, expand projects and methods; for Chevening-type awards, expand leadership and impact. Same life, different spotlight."] },
  { re: new RegExp("motivation letter|letter of motivation|cover letter.*(admission|scholarship)", "i"), a: ["Motivation letters (common for European programs) are shorter and more targeted than SOPs — usually one page answering: why this exact program, why you're a fit, and what you'll do with it. Name specific courses, labs, or tracks.", "Structure: 1 paragraph hook + goal, 1-2 paragraphs matching your experience to their curriculum, 1 paragraph on future plans. European reviewers value concreteness over storytelling flourish.", "Write a fresh 'why this program' section for every application — it's a third of the letter and the part committees read most carefully. The rest can be sensibly adapted."] },
  { re: new RegExp("scholarship interview|interview (prep|questions).*(scholarship|admission)|panel interview tips", "i"), a: ["Prepare tight 60-90 second answers to the five inevitable ones: tell us about yourself, why this field, why this country/program, your plan after, and a leadership/failure story. Practice out loud, not in your head.", "Know your own application deeply — panels probe what you wrote. If your essay mentions a project, be ready for three follow-up questions about its details and numbers.", "End strongly when asked 'any questions?': ask one thoughtful question about the program or alumni community. And a calm 'I don't know, but here's how I'd find out' beats bluffing every time. 🙂"] },
  { re: new RegExp("leadership essay|diversity (essay|statement)|community impact.*(essay|story)", "i"), a: ["Leadership isn't titles — it's initiative plus outcome. Organizing flood-relief tutoring for 20 kids is a stronger essay than 'vice president of club' with no story. Pick moments where you changed something.", "For diversity statements, your perspective as a Bangladeshi student is genuinely valuable — write about specific experiences (language, community, constraint, resourcefulness) and connect them to what you'll contribute on campus, not just what you overcame.", "Use one story per essay, told with scene and detail, rather than three summarized ones. Committees remember stories, not lists."] },
  { re: new RegExp("choose.*(major|subject|program)|which (subject|major|field).*study|confused.*(career|major)", "i"), a: ["Test cheaply before committing: one free online course, one small project, one conversation with someone in the field. Two weekends of honest exploration beats months of Facebook-group agonizing.", "Optimize for the intersection of aptitude, market, and tolerance for the daily grind — you'll do the boring parts of any field 80% of the time, so pick boring parts you can live with.", "At the master's stage, pivots are normal and explainable: a clear bridge sentence in your SOP ('my CS degree plus health-sector work leads me to health informatics') turns a zigzag into a narrative."] },
  { re: new RegExp("masters (or|vs|before) phd|direct phd|skip masters|phd after bachelor", "i"), a: ["US and Canadian PhDs happily take bachelor's graduates directly — and PhD funding is far better than master's funding, so if research is the goal, applying straight to PhD often makes financial sense.", "Europe, Japan, and Korea usually expect a master's first. So the answer partly depends on your target region, not just your readiness.", "Do a master's first if you're unsure about research, changing fields, or need to strengthen a weak undergrad record. Do direct PhD if you have research experience and a clear question you want five years with."] },
  { re: new RegExp("statement of research|research interest.*(statement|phd)|align.*research.*professor", "i"), a: ["For PhD applications, your research statement should name a problem area, show you know the current state (cite 3-5 key works naturally), sketch questions you'd pursue, and name 2-3 faculty whose work connects. It's a demonstration of taste, not a binding contract.", "Committees know your topic will evolve — they're evaluating whether you can think like a researcher: identify gaps, propose feasible approaches, and acknowledge limitations.", "Mirror the department's actual strengths. Naming professors who left, or areas the department doesn't cover, is the fastest way to signal you didn't do homework."] },
  { re: new RegExp("find (a )?mentor|talk to (alumni|seniors)|networking.*(scholarship|admission)|linkedin.*(alumni|outreach)", "i"), a: ["Find Bangladeshi alumni of your target program or scholarship on LinkedIn and send a short, specific message: who you are, one precise question, gratitude. Most seniors abroad reply generously to focused asks — vague 'please guide me' messages get ignored.", "One good mentor beats ten Facebook groups: they've seen real applications succeed and fail. Offer something back — even summarizing what you learned helps them help the next person.", "Scholarship bodies often run official alumni networks and pre-application webinars (Chevening and Fulbright both do) — attending gets you accurate answers and sometimes named contacts."] },
  { re: new RegExp("lesson plan|plan (a|my) (lesson|class)|teaching plan.*(class|topic)", "i"), a: ["Backward design works: decide what students should be able to DO by the end, design a quick check for it, then build activities toward it. Objectives like 'students will explain X with an example' beat 'cover chapter 5.'", "A reliable 45-minute skeleton: 5-min hook (question or demo), 15-min core teaching, 15-min guided practice, 5-min student summary, 5-min exit check. Talking less and checking more transforms retention.", "Plan for the room you actually have — 60 students, one board, occasional power cuts. Low-tech actives like think-pair-share and mini-whiteboards (laminated paper works) survive any infrastructure."] },
  { re: new RegExp("motivat(e|ing) students|students (don'?t|not) (care|study|listen)|engage.*(class|students)", "i"), a: ["Motivation follows relevance and small wins. Connect topics to students' actual lives (bazaar math, cricket statistics, local news) and structure tasks so weaker students taste success early — nothing motivates like recent progress.", "Learn names fast and notice effort publicly, ability privately. 'I saw you attempt every problem' is a safer, stronger motivator than ranking students against each other.", "Give students micro-choices — which problem to present, which example to explore. Autonomy is a documented motivation lever, and it costs a teacher nothing."] },
  { re: new RegExp("grading (fair|rubric|system)|how.*grade.*(essay|assignment|fairly)|marking (scheme|consistency)", "i"), a: ["Write a rubric before grading anything: 3-4 criteria with described levels. It speeds up marking, survives student complaints, and keeps your Monday and Thursday grading consistent.", "Grade one question across all papers rather than one paper fully at a time — it dramatically reduces drift and halo effects. Cover names if you can.", "Return work with one strength and one specific improvement noted; a wall of red ink teaches nothing. Feedback students can act on is the whole point of grading."] },
  { re: new RegExp("large class(es)?|teach.*(60|70|80|100) students|classroom management.*big", "i"), a: ["In large Bangladeshi classrooms, structure is survival: consistent routines for starting class, distributing materials, and asking questions save 10 minutes a day. Peer systems — row captains, pair-checking — multiply your reach.", "Use choral response and mini-whiteboards for whole-class checks instead of asking one student while sixty drift. Every student answering every question, even silently, keeps engagement up.", "Rotate deliberately: teach from different spots, and keep a simple mark on your attendance sheet for who you've called on, so the back benches get equal airtime across a week."] },
  { re: new RegExp("time manage.*(application|study)|balance.*(job|class).*application|overwhelmed.*(deadline|applying)", "i"), a: ["Treat applications like a course: 2 fixed hours on 3 fixed days beats 'whenever I'm free,' which becomes never. One focused hour on essays does more than four distracted ones.", "Batch by type: one week for test prep, one for professor emails, one for essay drafts. Context-switching between an SOP and GRE vocabulary in the same evening wastes both.", "Do the highest-resistance task first each session (usually essays), and track deadlines somewhere you see daily. Missing a deadline you knew about for months is the most preventable failure in this whole game."] },
  { re: new RegExp("rejected.*(scholarship|universit|visa)|handle rejection|reapply(ing)? after reject", "i"), a: ["Rejection is the base rate, not a verdict on you — strong candidates routinely get refused by half their list. Fulbright and Chevening are full of second-attempt winners; reapplying with an improved file is a known winning pattern.", "Do a cold autopsy after the sting fades: was it essays, scores, fit, or timing? Fix the one weakest link before the next cycle instead of vaguely 'trying harder.'", "If you got interviews but no award, you're close — the profile works, the delivery needs polish. If no interviews at all, the written materials need rebuilding. The pattern tells you where to invest. 💪"] },
  { re: new RegExp("scholarship scam|agent.*(fraud|fee|guarantee)|fake (scholarship|offer letter)", "i"), a: ["Red flags: anyone 'guaranteeing' a scholarship for a fee, application fees for government scholarships (MEXT, GKS, Chevening, Türkiye are all free), offers you never applied for, and pressure to pay quickly via bKash/personal accounts.", "Legitimate scholarships never ask money to release funds. If an email demands a 'processing fee' of a few hundred dollars to unlock your award — that's the whole scam.", "Verify everything at the source: the official scholarship website, the embassy, or the university's admissions email found on its own domain. A ৳2 lakh 'agent package' buys nothing you can't do better yourself with time and this checklist."] },
  { re: new RegExp("english (proficiency )?waiver|moi (letter|certificate)|medium of instruction.*(waive|instead)", "i"), a: ["Many universities waive IELTS if your degree was taught in English — you request a Medium of Instruction (MOI) letter from your registrar. Acceptance varies wildly: common in parts of Europe and some UK/Canadian schools, rare for US top programs and most visas.", "Even when the university accepts MOI, check the VISA rules separately — Australian and some UK routes require a formal test regardless of the university's flexibility.", "Email the specific admissions office and ask plainly: 'My bachelor's at X University was fully English-medium; do you waive the English requirement with an MOI letter?' Keep their written reply for your records."] },
  { re: new RegExp("proofread.*(sop|essay|application)|review my (sop|essay|statement)|feedback on.*(sop|essay)", "i"), a: ["Get three kinds of readers: someone in your field for substance, a strong English writer for clarity, and someone unfamiliar with your field — if they can follow your story, an admissions officer can. Then read it aloud yourself to catch clunky rhythm.", "Do targeted passes, not vague re-reads: one pass only for cutting redundancy, one for verbs (replace 'was involved in' with what you actually did), one for the opening and closing lines.", "Let a finished draft rest 48 hours before final review — distance reveals problems fresh eyes were too tired to see. And keep versions; sometimes draft three was better than draft six."] },
  { re: new RegExp("how.*stop procrastinat|beat procrastination|stop putting (things|it) off|procrastinating (again|so much|a lot)", "i"), a: ["Shrink the task until it's laughably small — 'open the file' instead of 'write the report'. Starting is 90% of the battle; momentum handles the rest.", "Try the 5-minute deal: work on it for just 5 minutes, then you're allowed to quit. You almost never will, but the permission to stop kills the dread.", "Procrastination is usually avoidance of discomfort, not laziness. Name what feels bad about the task (boring? scary? vague?) and fix that one thing first.", "Remove the decision: schedule the task at a specific time and place. 'Tomorrow at 9am at my desk' beats 'sometime this week' every time."], d: ["• Make the first step tiny and concrete", "• Commit to 5 minutes, no more", "• Schedule a specific time + place"] },
  { re: new RegExp("why (do i|am i).*procrastinat|reason.*procrastinat|cause of procrastination", "i"), a: ["Usually one of four culprits: the task is vague, it's boring, you fear doing it badly, or the reward is too far away. Diagnose which one and the fix becomes obvious.", "It's an emotion-management problem, not a time-management one — your brain is dodging short-term discomfort. Be kind to yourself, then make the first step painless.", "Often it's ambiguity. 'Work on thesis' triggers avoidance; 'write 3 bullet points for section 2' doesn't. Vague tasks feel heavier than they are."] },
  { re: new RegExp("can'?t (get )?start(ed)?|hard to (start|begin)|two.minute rule|how.*just start", "i"), a: ["Use the 2-minute rule: if the first step takes under 2 minutes, do it right now. Open the doc, write one ugly sentence — you're in.", "Lower the bar for starting, not for finishing. Tell yourself the goal is a terrible first draft; terrible drafts are allowed to exist.", "Set up the night before: leave the file open, the book on the desk, the code half-commented. Future-you should trip over the task, not search for it. 😊"] },
  { re: new RegExp("improve (my )?focus|can'?t (focus|concentrate)|stay focused|how.*concentrat", "i"), a: ["Focus is mostly environment design: phone in another room, one tab open, headphones on. Willpower is a backup plan, not a strategy.", "Work in short, protected sprints — 25 to 50 minutes with a visible timer. Knowing there's an end point makes your brain stop negotiating.", "Write down intrusive thoughts on a 'later list' instead of chasing them. Capturing the thought lets your brain release it and return to work.", "Check the basics first: sleep, water, food. A tired brain can't out-technique biology."] },
  { re: new RegExp("what.*deep work|deep work mean|cal newport", "i"), a: ["Deep work is distraction-free concentration on a cognitively demanding task — the mode where real progress happens. Cal Newport's rule of thumb: it's the work that would be hard for others to replicate.", "It's the opposite of answering messages while half-writing code. One hard task, zero interruptions, a fixed block of time — that's deep work.", "Think of it as training: like a muscle, your capacity for it grows. Most people start managing 1-2 solid hours a day, and that's already transformative."] },
  { re: new RegExp("schedule deep work|deep work (hours|routine|block)|how (much|many hours).*deep work", "i"), a: ["Protect 1-2 blocks of 90 minutes at your sharpest time of day — for most people that's the morning. Guard them like exam slots: no meetings, no chat.", "Start with one daily 60-minute block and grow it. Even elite researchers rarely sustain more than 4 hours of true deep work a day, so don't feel bad about starting small.", "Put deep work on your calendar as a real appointment with yourself. If it's not scheduled, shallow work will eat it."] },
  { re: new RegExp("what.*pomodoro|pomodoro technique|how.*pomodoro work", "i"), a: ["Pomodoro: 25 minutes of focused work, 5-minute break, repeat. After four rounds, take a longer 15-30 minute break. The timer turns a vague slog into a game.", "Pick one task, set a 25-minute timer, and do nothing else until it rings — not even 'quick' checks. The break after is mandatory, that's what keeps it sustainable.", "It works because it makes starting easy (it's only 25 minutes!) and makes distraction visible — every time you drift, the ticking timer calls you back. 🍅"] },
  { re: new RegExp("pomodoro (too short|length|duration)|longer pomodoro|(50|52|90).minute (session|block)|custom pomodoro", "i"), a: ["The 25/5 split is a default, not a law. Try 50/10 for coding or writing where warm-up costs are high, and keep 25/5 for tasks you dread.", "If you keep hitting flow right when the timer rings, lengthen the interval to 45-90 minutes. The rule that matters is: fixed work time, real break, repeat.", "Match the interval to the task: 25 minutes for admin and email, 50-90 for deep problem-solving. Experiment for a week and keep what sticks."] },
  { re: new RegExp("plan (my|the|a) day|daily plan(ning)?|organize my day|structure my day", "i"), a: ["Each evening, pick tomorrow's top 3 tasks — one big, two small. Do the big one first, before the day starts throwing surprises at you.", "Plan the day the night before in 5 minutes: 3 priorities, rough time slots, and one thing you'll deliberately NOT do. Morning-you will thank evening-you.", "Anchor the day around one 'must win' task. If everything else collapses but that gets done, the day was a success — that framing kills overwhelm."], d: ["• 3 tasks max: 1 big, 2 small", "• Big task first, before distractions wake up", "• Plan the night before"] },
  { re: new RegExp("plan (my|the|a) week|weekly plan(ning)?|organize my week", "i"), a: ["Take 20 minutes on Sunday: review deadlines, pick 3 weekly outcomes, and pre-assign your big tasks to specific days. The week goes better when Monday isn't a surprise.", "Plan the week by outcomes, not tasks — 'submit the abstract' beats a list of 14 chores. Then slot deep work blocks in before anything else claims the calendar.", "Leave 20% of the week unplanned. Buffer space is what keeps one surprise from wrecking five days of plans."] },
  { re: new RegExp("time.?block(ing)?|block(ing)? (my )?calendar|calendar block", "i"), a: ["Time blocking means giving every task an appointment: 9-11 thesis, 11-12 email, 2-4 project. A task with a time slot is 3x more likely to happen than one on a list.", "Block your calendar in 3 layers: fixed commitments first, then deep work, then shallow admin in the leftover gaps. Never the other way around.", "Keep blocks honest — if a task always overflows, the block was too small, not your discipline. Revise the plan mid-day without guilt; the plan serves you."] },
  { re: new RegExp("eisenhower|urgent.{0,15}important|priority matrix|quadrant.*(task|priorit)", "i"), a: ["The Eisenhower matrix sorts tasks by urgent vs important: do the urgent-important now, schedule the important-not-urgent, delegate the urgent-not-important, delete the rest.", "Its real power is quadrant 2 — important but not urgent (health, learning, planning). That's where your future is built, and it's the quadrant everyone neglects.", "Quick version: before starting anything, ask 'does this matter, and does it matter today?' Two yeses = do it. One yes = schedule or delegate. Zero = drop it."], d: ["• Urgent + important → do now", "• Important, not urgent → schedule it", "• Neither → delete without guilt"] },
  { re: new RegExp("eat the frog|hardest task first|worst task first|frog.*(task|morning)", "i"), a: ["Eat the frog: do your most dreaded, most important task first thing, before your willpower drains. Everything after feels easy by comparison.", "Pick tonight which frog you'll eat tomorrow, so the morning holds no decisions — just execution. One frog per day is plenty.", "If the frog is huge, eat a leg: do the first 30 minutes of it before anything else. Dread shrinks fast once you've started chewing. 🐸"] },
  { re: new RegExp("80.?20|pareto (principle|rule)|20 percent.*(result|effort)", "i"), a: ["The 80/20 rule: roughly 80% of results come from 20% of efforts. Find the few tasks that actually move your goals, and give them your best hours.", "Audit your week and ask: which 2-3 activities produced most of my progress? Do more of those, and shrink or drop the busywork that felt productive but wasn't.", "It's also a stopping rule — for many tasks, 80% quality is achievable fast and the last 20% costs most of the time. Ask whether that last 20% is worth it here."] },
  { re: new RegExp("how.*prioriti[sz]e|which task first|what.*(do|work on) first|prioriti[sz]ation framework", "i"), a: ["Fast method: for each task, score impact (1-3) and deadline pressure (1-3), multiply, do highest first. Thirty seconds of scoring beats an hour of dithering.", "Ask three questions: what breaks if I don't do this today? What moves my biggest goal? What only I can do? The task that answers all three wins.", "When everything feels equally urgent, pick the one that unblocks other people or other tasks first — dependencies before solo work."] },
  { re: new RegExp("too (many tasks|much to do)|overwhelm(ed|ing)|drowning in (work|tasks)|where.*even start", "i"), a: ["Brain-dump everything onto one page, then circle only what genuinely has a consequence this week. Overwhelm is often just an unsorted pile — sorting it shrinks it.", "Pick literally one task and do it for 25 minutes with the rest hidden from view. Overwhelm can't survive contact with singular focus.", "Take a breath — you don't have 40 tasks right now, you have one: deciding the next task. Do that, then the next. That's all anyone ever does. 💙"] },
  { re: new RegExp("build (a |new |good )?habit|start (a )?habit|form(ing)? habits|make.*(a habit|habitual)", "i"), a: ["Make it tiny, obvious, and scheduled: 'after breakfast, I read 2 pages at my desk'. Consistency at a small size beats intensity that fizzles in a week.", "Design the environment, not just the intention — put the book on your pillow, the running shoes by the door. Friction decides habits more than motivation does.", "Never miss twice. Missing once is life; missing twice is the start of a new (bad) habit. That single rule protects more habits than any app."] },
  { re: new RegExp("break (a |my )?bad habit|quit (a )?bad habit|stop (a )?bad habit", "i"), a: ["Make the bad habit invisible and inconvenient: log out, delete the app, move the snacks out of reach. Add 20 seconds of friction and half the battle is won.", "Replace, don't just remove — habits fill a need. Figure out what the habit gives you (stress relief? boredom escape?) and route that need somewhere healthier.", "Track the trigger: for three days, note when and where the habit strikes. Once you can see the cue, you can redesign around it."] },
  { re: new RegExp("habit stack(ing)?|attach.*habit|after.*existing habit|anchor habit", "i"), a: ["Habit stacking: bolt the new habit onto one you already do. 'After I pour my morning tea, I write one line in my journal.' The old habit becomes the reminder.", "The formula is: after [current habit], I will [new tiny habit]. Pick an anchor that happens daily at the same time, and keep the new habit under 2 minutes at first.", "Stack in the right order — put the new habit immediately after the anchor, in the same room. 'After lunch' is vague; 'after I put my plate in the sink' is a trigger."] },
  { re: new RegExp("broke (my )?streak|keep (a |my )?streak|lost my streak|don'?t break the chain", "i"), a: ["A broken streak isn't a broken habit — it's one data point. Restart today, and count total days done rather than consecutive days; that number never resets.", "Use the 'never miss twice' rule: one miss is an accident, two is a pattern. Your only job after a miss is to show up the very next day, even minimally.", "Protect streaks with a minimum viable version: on terrible days, 5 push-ups or one flashcard still counts. Streaks die from all-or-nothing thinking, not from busy days."] },
  { re: new RegExp("smart goal|set(ting)? (a )?goal|goal.?setting|how.*write.*goals", "i"), a: ["SMART goals: Specific, Measurable, Achievable, Relevant, Time-bound. 'Get fit' fails all five; 'run 5km three times a week until December' passes all five.", "Write the goal so a stranger could verify it. If you can't tell on a given day whether you're on track, the goal is a wish, not a goal.", "Set the goal, then immediately schedule the first action. A goal without a next step on the calendar is decoration."], d: ["• Specific & Measurable — verifiable by a stranger", "• Achievable & Relevant — matters and is realistic", "• Time-bound — has a real deadline"] },
  { re: new RegExp("long.?term goal|(life|5.year|five.year) (goal|plan)|big picture goal|vision for.*future", "i"), a: ["Work backwards: picture where you want to be in 3 years, then ask what must be true in 1 year, then in 3 months, then this week. Long-term goals only work when they cash out into this week's actions.", "Limit yourself to 2-3 long-term goals at once. Ten goals is zero goals — attention divided ten ways moves nothing.", "Review long-term goals monthly, not daily. Daily is for actions; obsessing over the distant summit just makes the climb feel longer."] },
  { re: new RegExp("goals? vs systems?|system over goal|process (over|vs) (goal|outcome)|focus on.*process", "i"), a: ["Goals set the direction; systems make the progress. 'Publish a paper' is the goal — 'write 300 words every morning' is the system that actually gets you there.", "If you find goals demotivating, shift your identity to the system: don't chase 'finish the app', become 'someone who commits code daily'. Winners and losers often have the same goals; the systems differ.", "A good test: could you make progress this week even if you forgot the goal existed? If yes, you have a system. If no, you have a hope."] },
  { re: new RegExp("note.?taking (method|system|tips)|take (better|good) notes|how.*take notes|cornell (method|notes)", "i"), a: ["Take notes in your own words, not transcription — rephrasing is where the learning happens. If you're copying verbatim, you're a photocopier, not a student.", "Try the Cornell method: notes on the right, key questions in the left margin, a 2-line summary at the bottom. The margin questions double as instant flashcards later.", "Fewer, better notes: capture ideas, decisions, and questions — not everything said. A note you'll actually re-read beats ten pages you never open."] },
  { re: new RegExp("zettelkasten|second brain|personal knowledge (base|management)|organize (my )?notes", "i"), a: ["A 'second brain' just means one trusted place where notes live and link together — Obsidian, Notion, or even a folder of text files. The tool matters far less than the habit of putting things in and linking them.", "Zettelkasten in one line: one idea per note, in your own words, linked to related notes. The links are the magic — that's how old notes resurface exactly when they're useful.", "Don't over-engineer the system before you have notes. Capture messily for a month, then organize what actually accumulated. Structure should follow content."] },
  { re: new RegExp("todo list (mess|hygiene|too long)|clean (up )?(my )?todo|task list.*(overwhelm|huge|ignore)|stale (todo|task)s", "i"), a: ["Todo hygiene rule: every item must start with a verb and be doable in one sitting. 'Thesis' isn't a task; 'draft intro paragraph' is.", "If your list has items older than a month, hold a funeral: do it now, schedule it, or delete it. A list you don't trust is a list you'll stop reading.", "Keep two lists: a short 'today' list (3-5 items) and a big 'someday' backlog. Working straight off the backlog is how todo lists become anxiety generators."] },
  { re: new RegExp("(best )?todo app|paper (vs|or) (digital|app)|which task (manager|app)|notion (vs|or) todoist", "i"), a: ["The best todo tool is the one you'll check every day — for some that's Todoist, for others a ৳20 notebook. Switching apps is procrastination in a productivity costume.", "Digital wins for recurring tasks and reminders; paper wins for daily focus because it can't ping you. Many people thrive with a hybrid: digital backlog, paper 'today' card.", "Pick one tool, use it for 30 days without switching, then judge. Most 'the app isn't working' problems are actually 'I stopped opening it' problems."] },
  { re: new RegExp("deadline (tomorrow|tonight|panic)|due (tomorrow|in hours|tonight)|last minute.*(deadline|submit)|cram(ming)? for (a )?deadline", "i"), a: ["Triage first: list what's strictly required for submission, cut everything optional, and work the required list top-down. Done and adequate beats unfinished and brilliant.", "Set a hard stop 1-2 hours before the real deadline for formatting, uploading, and disasters. Submission logistics eat more last-minute deadlines than the actual work does.", "Work in 45-minute bursts with 5-minute breaks even under pressure — panic-grinding for 6 straight hours produces worse output than paced sprints. You've got this. 💪"] },
  { re: new RegExp("planning fallacy|estimate.*(time|task)|always take[s]? longer|underestimat.*(time|how long)", "i"), a: ["The planning fallacy is universal: we estimate best-case, reality delivers average-case. Fix: estimate normally, then multiply by 1.5-2x. It feels pessimistic and turns out accurate.", "Estimate from evidence, not imagination — how long did the last similar task actually take? Past-you is a better forecaster than optimistic-you.", "Break the task into pieces and estimate each; small chunks are estimated far more accurately than one big blob, and the sum is usually eye-opening."] },
  { re: new RegExp("multitask(ing)?|(do|doing) (two|multiple) things at once|juggling tasks", "i"), a: ["Multitasking is a myth — the brain rapidly switches, and each switch costs time and error rate. What feels like doing two things is doing both badly, slower.", "The only real multitasking that works pairs a mindless task with a mental one: walking + podcast, folding laundry + lecture audio. Two cognitive tasks always fight.", "Try single-tasking for one day as an experiment: one tab, one task, notifications off. Most people are startled by how much lighter the day feels."] },
  { re: new RegExp("context switch(ing)?|switching between (tasks|projects)|attention residue|too many projects at once", "i"), a: ["Every switch leaves 'attention residue' — part of your brain stays on the old task for 10-20 minutes. Four switches an hour means you never actually arrived anywhere.", "Batch by context: all messages in one block, all writing in another, all errands together. Group similar work and the switching tax mostly disappears.", "Limit work-in-progress: 2-3 active projects max. Everything else goes to a parked list with a note on the exact next step, so resuming later is cheap."] },
  { re: new RegExp("morning routine|start (my|the) (day|morning) (right|well)|first (hour|thing) in the morning", "i"), a: ["A good morning routine has three jobs: wake the body (water, light, movement), skip the noise (no phone for the first 30 minutes), and start the day's #1 task early. Everything else is garnish.", "Keep it short and repeatable — a 15-minute routine you do daily beats a 90-minute aspirational one you do twice. Consistency is the whole point.", "Decide the morning the night before: clothes out, task chosen, desk clear. A great morning is mostly manufactured the previous evening."] },
  { re: new RegExp("night owl|(morning|evening) person|chronotype|work better at night", "i"), a: ["Don't fight your chronotype — schedule around it. If you're sharpest at 10pm, protect that slot for deep work and stop feeling guilty about slow mornings.", "Being a night owl is fine; being a sleep-deprived owl is not. Late schedule + consistent 7-8 hours is sustainable; late schedule + 8am classes needs a gradual shift, 15 minutes earlier per night.", "Find your peak by tracking for a week: note your energy 1-5 every 2 hours. Then move your hardest work into your top window — that one change beats most productivity hacks."] },
  { re: new RegExp("sleep (better|schedule|deprived)|can'?t sleep|fix (my )?sleep|insomnia", "i"), a: ["The highest-leverage fix: same wake-up time every day, even weekends. A stable anchor point drags the whole sleep schedule into place within two weeks.", "Screens off 30-60 minutes before bed, room dark and cool, no big meals late. Boring advice, but it's boring because it works.", "Treat sleep as productivity infrastructure, not a luxury — one bad night costs more focus than any technique can recover. Protect it like a deadline."] },
  { re: new RegExp("afternoon (slump|crash|dip)|energy manage(ment)?|low energy.*(afternoon|day)|tired after lunch", "i"), a: ["Manage energy, not just time: put creative work in your peak hours, admin in the dip. The 2-4pm slump is biology — schedule email there, not your thesis.", "For the slump itself: a 10-minute walk, sunlight, water, and a lighter lunch beat a third coffee. Caffeine after 2pm often just taxes tonight's sleep.", "A 15-20 minute nap (not longer) can genuinely reboot the afternoon. Set an alarm — past 30 minutes you wake groggier than you started."] },
  { re: new RegExp("burnout (signs|symptoms)|am i burn(ed|t) out|feel(ing)? burn(ed|t) out", "i"), a: ["Classic signs: exhaustion that rest doesn't fix, cynicism about work you used to care about, and feeling ineffective despite long hours. If two of three sound familiar, take it seriously.", "Burnout creeps — the tell is when even easy tasks feel heavy and recovery weekends stop working. That's a signal to cut load, not to push harder.", "Check the difference: tiredness ends with sleep; burnout survives a holiday. If it's the second one, the fix is reducing demands, not optimizing your schedule."] },
  { re: new RegExp("(prevent|avoid|recover from) burnout|burnout recovery|sustainable pace", "i"), a: ["Prevention is rhythm: real breaks daily, one true day off weekly, and at least one hobby with zero productivity value. You can't sprint a marathon.", "If you're already burnt: cut commitments by a third (yes, actually), sleep first, and add back only what earns its place. Recovery needs subtraction before optimization.", "Watch the leading indicators — skipped meals, dropped hobbies, 'I'll rest after this deadline' three deadlines in a row. Intervene at the pattern, not the collapse. 🌱"] },
  { re: new RegExp("say(ing)? no|turn(ing)? down (request|people)|can'?t refuse|overcommit(ted|ting)", "i"), a: ["Every yes is a no to something you've already promised — usually to your own goals. Frame it that way and 'no' becomes an act of keeping your word.", "Use a warm, fast formula: 'Thanks for thinking of me — I can't take this on right now.' No long excuse; explanations invite negotiation.", "Try 'let me check and get back to you' as a default. A 24-hour buffer converts most pressured yeses into calm, honest nos."] },
  { re: new RegExp("too many meetings|meeting overload|(useless|pointless) meetings|fewer meetings", "i"), a: ["Before accepting any meeting, ask: is there an agenda, and am I needed for a decision? No agenda or no decision role — decline or ask for the notes instead.", "Batch meetings into one or two afternoon blocks and defend your mornings. A day fragmented by five scattered meetings has zero deep work in it.", "Default to 25 or 50 minutes instead of 30/60 — the buffer between calls is where your brain and your notes catch up. And propose async (a doc or voice note) for anything that's just a status update."] },
  { re: new RegExp("email overload|inbox (zero|full|overflow)|too many emails|manage (my )?(email|inbox)", "i"), a: ["Check email at 2-3 fixed times a day instead of living in it. An inbox open all day is a todo list other people write for you.", "Use the 2-minute triage: under 2 minutes, answer now; longer, move it to your task list with a deadline; irrelevant, archive instantly. Touch each email once.", "Unsubscribe ruthlessly for one week — every newsletter you don't read is a tiny recurring tax. Ten unsubscribes saves hours a year."] },
  { re: new RegExp("study.{0,10}work balance|balance.*(study|studies).*(work|job)|part.time (job|work).*stud", "i"), a: ["Fix your study blocks in the calendar first, then fit work around them — not the reverse. Whatever gets scheduled first wins the week.", "Use transition rituals: five minutes to close one context (note where you stopped, next step) before opening the other. The balance problem is often really a switching problem.", "Be honest about total capacity: classes + job + commute + sleep leaves what it leaves. Plan inside reality and you'll feel in control instead of perpetually behind."] },
  { re: new RegExp("startup (and|while) (stud|universit|class)|founder.*student|balance.*startup.*(class|degree|exam)", "i"), a: ["Give the startup fixed, protected slots — say 6-9pm and weekends — rather than 'whenever I'm free'. Free time doesn't exist for a student founder; only allocated time does.", "During exam weeks, pre-plan a 'startup minimum': the 2-3 things that keep it alive (answering customers, one deploy) and consciously pause the rest. A planned pause beats a guilty stall.", "Sync the calendars: know your exam dates and demo days months out, and never schedule a launch the week of finals. Most student-founder crises are calendar collisions someone could have seen coming."] },
  { re: new RegExp("(no|lost|zero) motivation|don'?t feel like (working|doing)|motivation dip|unmotivated", "i"), a: ["Motivation follows action more than it precedes it — start badly for 10 minutes and it usually shows up mid-task. Waiting to feel like it is waiting for weather.", "On low days, shrink the standard: do the minimum viable version of your plan. Keeping the routine alive at 20% beats abandoning it at 0%.", "Check whether the dip has a cause: sleep debt, no visible progress, or a goal you've quietly stopped believing in. Each has a different fix, and none of them is 'try harder'. 💙"] },
  { re: new RegExp("discipline (vs|over) motivation|rely on (discipline|willpower)|don'?t need motivation", "i"), a: ["Motivation is a spark; systems are the engine. Build routines that run on autopilot — same time, same place, same trigger — and you'll work fine on days motivation doesn't show.", "Even 'disciplined' people mostly just have fewer decisions to make: pre-chosen tasks, prepared environments, default schedules. Discipline is largely design.", "Use motivation when you have it — to build the systems you'll lean on when you don't. That's its highest-value use."] },
  { re: new RegExp("accountability (partner|buddy)|(someone|need) to hold me accountable|body doubling|study (buddy|partner)", "i"), a: ["An accountability partner works best with structure: a fixed weekly check-in, specific commitments stated in advance, and honest reporting. Vague 'keep me accountable' fizzles in two weeks.", "Try body doubling — working alongside someone (in person or on a video call) doing their own work. The quiet social pressure is remarkably effective against drifting.", "Make commitments public and specific: 'I'll send you the draft by Friday 8pm.' A named deliverable with a witness is worth ten private intentions."] },
  { re: new RegExp("track (my )?progress|measure (my )?progress|progress track(er|ing)|am i making progress", "i"), a: ["Track one leading metric per goal — words written, problems solved, sessions completed — not just outcomes. Outcomes lag; inputs are what you control daily.", "Keep a 'done list' alongside the todo list. On hard weeks, seeing what you actually finished is the antidote to 'I got nothing done' distortion.", "Review the numbers weekly, not hourly. Daily fluctuation is noise; the weekly trend is signal."] },
  { re: new RegExp("weekly review|review (my|the) week|friday (review|retro)|sunday planning", "i"), a: ["A weekly review is 30 minutes, three questions: what got done, what stalled and why, and what are next week's top 3? It's the cheapest high-leverage habit that exists.", "Anchor it to a fixed slot — Friday afternoon or Sunday evening — with a small ritual (tea, music) so it actually happens. Reviews skipped 'just this week' die quietly.", "Close all loops during the review: empty the inbox, update the task list, capture loose thoughts. Starting Monday with a clear system is the real payoff."], d: ["• What worked this week?", "• What stalled, and why?", "• Top 3 for next week?"] },
  { re: new RegExp("break (down )?(a )?big (project|task|goal)|project feels (huge|too big)|chunk(ing)? (a )?(task|project)|milestone", "i"), a: ["Work backwards from the deliverable: define 3-5 milestones, then break only the first milestone into next actions. Detailed-planning the distant parts is wasted effort — they'll change.", "Every chunk should be finishable in one sitting and start with a verb. If you can't picture yourself doing it, it's still a project wearing a task costume.", "Find the 'walking skeleton' — the ugliest end-to-end version of the whole thing — and build that first. It kills unknowns early and makes everything after feel like polishing."] },
  { re: new RegExp("stuck on (a )?(problem|task|bug)|can'?t (solve|figure) (it|this) out|hitting a wall|banging my head", "i"), a: ["Explain the problem out loud to a rubber duck, a friend, or a blank note. Forcing it into words exposes the gap in your thinking about half the time.", "Step away deliberately — a walk, a shower, a different task for an hour. Diffuse-mode thinking solves what staring cannot; the answer often arrives mid-walk.", "Timebox the struggle: 30 more focused minutes, then you must either change approach or ask someone. Heroic solo grinding past that point is usually ego, not strategy."] },
  { re: new RegExp("blocked (on|by|waiting)|waiting (on|for) (someone|approval|reply)|dependency.*block", "i"), a: ["When blocked by someone, send a specific, easy-to-answer nudge ('yes/no on X by Thursday?') and set a follow-up reminder. Then switch to your parallel track — never let one blocker idle the whole day.", "Keep a 'blocked' list separate from your todo list, each item with who you're waiting on and when to chase. Blockers you track come back; blockers you memorize evaporate.", "Ask yourself: can I do a rough version with assumptions and swap in the real input later? Often 80% of the work doesn't actually need the thing you're waiting for."] },
  { re: new RegExp("perfectionis[mt]|everything (must|has to) be perfect|polish(ing)? too much|never feels (good enough|finished)", "i"), a: ["Define 'done' before you start — a checklist of what the output must have. Without a finish line, perfectionism will keep moving it forever.", "Set a quality budget: this task deserves 2 hours of polish, not 8. Perfectionism isn't high standards, it's unlimited standards, and limits are the cure.", "Ship the 85% version and let feedback tell you which 15% actually mattered. Your guess about what needs perfecting is usually wrong anyway."] },
  { re: new RegExp("done is better than perfect|just ship it|when to (ship|publish|submit)|good enough", "i"), a: ["Ship when it's useful, not when it's flawless. A submitted draft can be improved; a perfect draft in your head helps nobody.", "Ask: what's the actual cost of a small flaw here versus the cost of another week's delay? For most student and startup work, delay costs far more.", "Set a shipping ritual: final read-through, one checklist pass, send, and then close the tab. No re-reading after submission — that road leads nowhere good. 🚀"] },
  { re: new RegExp("phone (distract|addict)|check(ing)? (my )?phone (too much|constantly)|put (my )?phone (away|down)|screen time too (high|much)", "i"), a: ["Distance beats discipline: phone in another room, or in a bag across the room, while you work. Every metre of distance is worth an hour of willpower.", "Make the phone boring: grayscale mode, home screen stripped to tools only, social apps buried in a folder or deleted (use the browser version — the extra friction is the feature).", "Give the checking urge a lawful outlet: a 5-minute phone break every hour, on a timer. Scheduled indulgence is far easier to keep than total prohibition."] },
  { re: new RegExp("social media (addict|distract|waste)|doom.?scroll|too much (facebook|instagram|tiktok|reels)|quit social media", "i"), a: ["Try a 7-day experiment rather than quitting forever: log out everywhere, delete the apps, and notice what you reach for in the gaps. The data will tell you what role it was really playing.", "Replace the trigger moment: doomscrolling usually starts at specific times (waking, meals, bed). Put a book, a puzzle app, or flashcards in exactly those slots.", "Use it on your terms — specific times, specific purpose, timer set. 'I'll check messages at 1pm for 15 minutes' is control; 'just a quick look' is how an hour disappears."] },
  { re: new RegExp("spaced repetition|flashcard (schedule|app)|forgetting curve", "i"), a: ["Spaced repetition schedules reviews just before you'd forget: after a day, then 3 days, a week, a month. Anki automates it — 15 minutes daily beats hours of cramming for long-term retention.", "Make cards yourself, one atomic fact or concept each, in your own words. Downloading someone else's deck skips the encoding step where most learning happens.", "The catch: it only works daily. A 200-card backlog after a skipped week is how most people quit — keep the daily load small enough that you never dread it."] },
  { re: new RegExp("memori[sz]e (better|faster)|active recall|remember what i (study|read)|retain (more|information)", "i"), a: ["Active recall beats rereading by a mile: close the book and write or say what you remember, then check. The struggle to retrieve is the learning — highlighting is mostly decoration.", "Test yourself before you feel ready. Getting it wrong and correcting sticks better than getting it right after five rereads.", "Teach it to someone (or an imaginary someone). If you can explain it simply without notes, you know it; where you stumble is exactly what to review."] },
  { re: new RegExp("keep forgetting (things|tasks)|capture (system|everything)|ideas slip (away|my mind)|write things down", "i"), a: ["Adopt one capture point — a notes app or a pocket notebook — and dump every task, idea, and commitment there the moment it appears. Your brain is for having ideas, not storing them.", "The rule is 'capture now, sort later'. Trying to organize in the moment kills the habit; a messy inbox you process each evening works far better.", "Forgetting isn't a memory flaw, it's a system gap. One trusted place + one daily 5-minute sort = nothing important slips again."] },
  { re: new RegExp("parkinson'?s law|timebox(ing)?|work expands|artificial deadline", "i"), a: ["Parkinson's Law: work expands to fill the time available. Give a task 3 days and it takes 3 days; give it an honest afternoon and it often fits.", "Timebox aggressively: decide the time budget before starting ('this email gets 10 minutes, this section gets 90') and set a visible timer. Constraint creates focus.", "Use fake deadlines with real teeth: promise the draft to a friend by 6pm, book the review meeting before the work is done. External stakes make timeboxes hold."] },
  { re: new RegExp("always last minute|only work under pressure|need (a )?deadline to work|leave everything (until|till) the end", "i"), a: ["If you only work under pressure, manufacture pressure earlier: split the project into weekly deliverables, each promised to someone real. You keep the adrenaline, minus the all-nighter.", "Last-minute work feels efficient because you remember the focus and forget the quality lost and options foreclosed. Compare your rushed output to your paced output honestly — once.", "Try 'scheduled panic': give yourself a compressed, timed 3-hour sprint a week before the deadline, simulating the crunch. Same intensity, but with time left to fix what it produces."] },
  { re: new RegExp("batch(ing)? (tasks|work)|group similar tasks|admin (block|day)|errand batching", "i"), a: ["Batch shallow tasks — email, forms, payments, errands — into one or two fixed blocks a day. Twenty small tasks done together take half the time of twenty scattered ones.", "Theme your days if you can: Monday for meetings, Tuesday-Thursday deep work, Friday admin and review. Themes eliminate the 'what now?' decision dozens of times a week.", "Keep a running 'batch list': when a small task appears mid-focus, jot it down instead of doing it. Then clear the whole list in one satisfying sweep later."] },
  { re: new RegExp("(workspace|desk) setup.*(focus|productiv)|study environment|where.*(study|work) best|distraction.free (space|setup)", "i"), a: ["Your environment votes on your behavior all day: clear desk, one screen of relevant windows, water within reach, phone out of sight. Set the stage before the performance.", "If home is noisy, find your 'focus venue' — a library, a quiet café, a corner that your brain associates only with work. Location-based habits are among the strongest.", "Try a 'startup ritual': same drink, same playlist, same desk arrangement each session. After a couple of weeks, the ritual itself pulls you into focus mode."] },
  { re: new RegExp("music while (studying|working)|(lofi|instrumental).*(focus|study)|listen to.*while.*(work|study)|noise.*(focus|concentrat)", "i"), a: ["Rule of thumb: music with lyrics hurts reading and writing, is neutral for routine work, and instrumental/lofi helps most people mask distracting noise. Match the sound to the task.", "For deep verbal work (writing, memorizing), try silence or brown noise instead — your language centers can't fully ignore words being sung at them.", "Use one dedicated focus playlist and only play it while working. It becomes a Pavlovian on-switch — press play, brain shifts gears. 🎧"] },
  { re: new RegExp("boring task|tedious (work|task)|make.*(chore|task) (fun|bearable)|temptation bundling", "i"), a: ["Temptation bundling: pair the boring task with something you enjoy — your favorite tea only while doing expenses, that playlist only while formatting references.", "Gamify it: race a timer ('all citations fixed in 20 minutes?'), or count units done and try to beat yesterday. Boredom hates a scoreboard.", "Ask if it can be shrunk, automated, or batched first. The most productive way to do a boring task is often to make it smaller before you make yourself do it."] },
  { re: new RegExp("flow state|get (into|in) (flow|the zone)|lose track of time.*work", "i"), a: ["Flow needs three ingredients: a clear goal, immediate feedback, and difficulty just above your comfort level. Too easy is boredom, too hard is anxiety — tune the challenge.", "Protect the runway: flow takes 15-20 undisturbed minutes to enter and one notification to exit. Long unbroken blocks aren't a luxury, they're the entry fee.", "Don't chase flow directly — set up the conditions (one clear task, no interruptions, slight stretch) and let it arrive. Watching for it scares it off."] },
  { re: new RegExp("take (better|real) breaks|rest (properly|without guilt)|break(s)? between (study|work)|feel guilty resting", "i"), a: ["A real break changes the channel: move your body, look at something far away, step outside. Scrolling is a context switch, not a rest — your attention never actually got off duty.", "Schedule rest like work: it's not the absence of productivity, it's the maintenance of it. An hour of guilt-free rest restores more focus than three hours of guilty half-rest.", "Follow rough cycles: 60-90 minutes on, 10-15 genuinely off. Your brain consolidates and problem-solves during the off-phase — breaks are when half the thinking happens."] },
  { re: new RegExp("wake up earl(y|ier)|become (a )?morning person|stop hitting snooze|5 ?am (club|routine)", "i"), a: ["Waking earlier starts the night before — shift bedtime and wake time together in 15-minute steps. Forcing a 5am start on a 1am bedtime just relocates your tiredness.", "Beat snooze with physics: alarm across the room, lights on a timer, water by the bed. The goal is making getting up easier than lying there.", "Give the early hour a specific, appealing purpose — a project you love, a quiet walk. 'Wake at 6 to do something I want' survives; 'wake at 6 on principle' doesn't."] },
  { re: new RegExp("study (plan|schedule) for exam|exam (prep|revision) (plan|schedule)|how.*prepare for exams?|revision timetable", "i"), a: ["Plan backwards from exam day: list topics, weight them by marks and your weakness, and spread them across the days left — with the final 2 days reserved for practice papers and review only.", "Study in retrieval mode: past papers and self-testing from day one, not just at the end. One practice paper teaches you more about your gaps than three rereads of notes.", "Interleave subjects rather than marathoning one — two subjects a day in alternating blocks builds stronger memory than single-subject binges, even though it feels harder."] },
  { re: new RegExp("stay motivated.*long (project|term)|losing steam.*(project|goal)|months.long project.*motivat|marathon project", "i"), a: ["Long projects die in the middle, so engineer visible progress: a progress bar, a milestone chart, a done-list. The brain needs proof of movement to keep investing.", "Set process milestones you fully control ('draft 4 chapters') rather than outcome ones ('get accepted'). Celebrate each — momentum is built from marked wins, not from grit alone.", "Reconnect with the why monthly: write one paragraph on why this project matters to you and reread it on flat days. Purpose fades from view unless you deliberately look at it."] },
  { re: new RegExp("turn off notifications|notification (overload|manage)|constant (pings|interruption)|do not disturb.*(work|focus)", "i"), a: ["Default everything to silent, then whitelist the 3-5 people and apps that genuinely warrant interruption. Notifications should be exceptions you chose, not a stream you endure.", "Use Do Not Disturb on a schedule — automatically on during your deep work blocks and after 10pm. Automation beats remembering.", "Batch the checking: a phone glance at the top of each hour catches everything truly urgent. In practice, almost nothing can't wait 55 minutes."] },
  { re: new RegExp("celebrate (small )?wins|reward (myself|system)|acknowledge progress|never feel accomplished", "i"), a: ["Close each day by writing down three things you finished, however small. The brain discounts un-noted progress to zero — the list is how you keep the credit you earned.", "Attach small rewards to real milestones: finish the section, then the good coffee or an episode. Rewards after work train the habit; rewards instead of work train the opposite.", "Celebrating wins isn't indulgence, it's fuel management — recognition is what makes effort feel worth repeating. Even a quiet 'that was solid work' to yourself counts. 🎉"] },
  { re: new RegExp("what( is|'s) (ai|artificial intelligence)|define artificial intelligence|explain ai to me", "i"), a: ["AI is software that does things we'd normally call 'smart' — recognizing patterns, making predictions, or deciding what to do next. It's less magic, more math applied at scale.", "Artificial intelligence means teaching computers to handle tasks that usually need human judgment, like spotting a good opportunity or translating a sentence. Under the hood it's mostly statistics and optimization.", "Think of AI as a very fast, very patient pattern-spotter. It doesn't 'understand' like you do, but it can learn useful rules from lots of examples."] },
  { re: new RegExp("what( is|'s) machine learning|define machine learning|explain ml basics|machine learning in simple", "i"), a: ["Machine learning is when a computer learns rules from examples instead of being hand-coded. Show it 1,000 past scholarship applications and outcomes, and it learns what tends to win.", "ML flips normal programming: instead of writing the rules, you give data plus answers, and the algorithm figures out the rules itself.", "It's pattern-learning from data. The more good examples you feed it, the better it gets at predicting the next case — like a student improving with practice problems. 📚"] },
  { re: new RegExp("what( is|'s) deep learning|define deep learning|deep learning explained", "i"), a: ["Deep learning is machine learning using neural networks with many stacked layers. Each layer learns slightly more abstract patterns — edges become shapes, shapes become faces.", "It's ML's heavy machinery: big layered networks that learn features automatically from raw data like images, audio, or text, instead of needing humans to hand-craft them.", "Deep learning shines when you have tons of data and messy inputs. For a small tracker like this, simpler models are often smarter — deep nets would be overkill."] },
  { re: new RegExp("ai vs ml|ml vs deep learning|difference between ai.*(ml|machine learning)|ai.*ml.*deep learning", "i"), a: ["Think of them as nesting dolls: AI is the big goal (smart behavior), machine learning is one way to get there (learning from data), and deep learning is one flavor of ML (big neural networks).", "AI is the umbrella term, ML is the subset that learns from examples, and deep learning is the subset of ML that uses many-layered neural nets. Every deep learning model is ML, but not every AI is either.", "AI can even be simple rules — like me offline! ML learns from data, and deep learning is ML with deep neural networks for complex stuff like images and language."], d: ["• AI ⊃ ML ⊃ Deep Learning", "• Rules-based systems are AI without ML", "• Deep learning needs lots of data"] },
  { re: new RegExp("supervised vs unsupervised|what( is|'s) supervised learning|what( is|'s) unsupervised learning", "i"), a: ["Supervised learning has labeled answers — 'this application won, this one lost' — so the model learns to predict labels. Unsupervised has no answers; it just finds structure, like grouping similar opportunities together.", "Supervised is learning with an answer key; unsupervised is exploring without one. Predicting your win chance is supervised; clustering your deadlines into 'types' is unsupervised.", "If you know the outcome for each example, it's supervised. If you're just hunting for hidden patterns or groups, it's unsupervised."] },
  { re: new RegExp("classification vs regression|difference.*classification.*regression|predict category or number", "i"), a: ["Classification predicts a category (win/lose, spam/not spam); regression predicts a number (how much ৳ you'll earn, tomorrow's temperature). Same idea, different output type.", "Ask: is the answer a label or a quantity? 'Will I get this grant?' is classification. 'How many days until I hear back?' is regression.", "Classification sorts things into buckets; regression draws a line through numbers. Your win-probability score is actually classification wearing a probability hat."] },
  { re: new RegExp("what( is|'s) logistic regression|logistic regression explained|how does logistic regression work", "i"), a: ["Logistic regression takes a weighted sum of your features and squashes it into a probability between 0 and 1. Despite the name, it's a classifier — and a wonderfully honest, interpretable one.", "It's the workhorse of yes/no prediction: each factor (deadline pressure, fit, past wins) gets a weight, they're added up, and a sigmoid curve turns the total into a percentage.", "It's how I estimate your win chances! Simple, fast, and you can actually see which factors push the probability up or down — no black box."] },
  { re: new RegExp("what( is|'s) linear regression|linear regression explained|fit(ting)? a line.*data", "i"), a: ["Linear regression fits the best straight line through your data points so you can predict a number from inputs — like estimating award size from application effort.", "It finds the line that minimizes the total prediction error. Old, simple, and still one of the most used tools in data science.", "It's drawing a trend line, but done rigorously: the math picks the slope and intercept that fit your data best."] },
  { re: new RegExp("what( is|'s) overfitting|overfitting explained|model memoriz|why.*overfit", "i"), a: ["Overfitting is when a model memorizes the training data instead of learning general patterns — perfect on old examples, terrible on new ones. Like cramming answers instead of understanding the subject.", "An overfit model treats noise as signal. It looks brilliant in training and flops in the real world — the classic data science heartbreak. 💔", "It's tailoring a suit so tightly to one person that it fits nobody else. The fixes: more data, simpler models, regularization, and honest testing on held-out data."] },
  { re: new RegExp("what( is|'s) underfitting|underfitting explained|model too simple", "i"), a: ["Underfitting is the opposite of overfitting: the model is too simple to capture the real pattern, so it's bad on training data AND new data.", "It's like summarizing a novel in three words — you've missed the plot. The fix is a richer model, better features, or more training.", "If your model performs poorly everywhere, it's underfitting. Add complexity or better features until it starts actually learning the pattern."] },
  { re: new RegExp("train.?test split|training.*testing data|hold.?out set|why split.*data", "i"), a: ["You split your data — say 80% to train the model, 20% hidden away to test it. The test set answers the only question that matters: does it work on data it's never seen?", "It's like studying from past papers but sitting a fresh exam. Testing on training data is grading yourself on questions you already memorized.", "Train on one slice, test on an untouched slice. Never let the model peek at the test set, or your accuracy numbers become flattering lies."] },
  { re: new RegExp("cross.?validation|k.?fold|what( is|'s) cv in ml", "i"), a: ["Cross-validation splits your data into k folds, trains on all-but-one, tests on the leftover, and rotates. You get a more reliable performance estimate than one lucky split.", "It's running the exam five times with different question sets and averaging the grade — much harder to fool than a single test.", "Especially valuable with small datasets, where one unlucky split could mislead you. Every data point gets a turn as test data."] },
  { re: new RegExp("accuracy vs precision|precision (and|vs\\.?) recall|what( is|'s) recall in ml", "i"), a: ["Accuracy is how often you're right overall — but it's misleading when one class dominates. Precision asks 'of my yes-predictions, how many were truly yes?'; recall asks 'of all true yeses, how many did I catch?'", "Precision is about not crying wolf; recall is about not missing the wolf. A deadline reminder should favor recall — better a spare nudge than a missed scholarship!", "If 95% of applications lose, a model that always says 'lose' is 95% accurate and 100% useless. That's why precision and recall exist."], d: ["• Precision: trust in your positive calls", "• Recall: coverage of real positives", "• There's usually a trade-off between them"] },
  { re: new RegExp("what( is|'s) f1 score|f1.?score explained|harmonic mean.*precision", "i"), a: ["F1 is the harmonic mean of precision and recall — one number that's only high when both are decent. It punishes lopsided models.", "It's the diplomat between precision and recall: you can't score well on F1 by maxing one and ignoring the other.", "Use F1 when classes are imbalanced and both false alarms and misses hurt. It keeps you honest."] },
  { re: new RegExp("confusion matrix|true positive.*false|false positive vs false negative", "i"), a: ["A confusion matrix is a 2x2 scorecard: true positives, true negatives, false positives (false alarms), and false negatives (misses). It shows exactly HOW your model is wrong, not just how often.", "It's the model's report card broken down by error type. Two models with identical accuracy can have wildly different confusion matrices — and wildly different consequences.", "False positive: I flag a dud opportunity as golden. False negative: I miss a real gem. The matrix counts both so you know which mistake you're making more."] },
  { re: new RegExp("what( is|'s) calibration|calibrated (probabilit|model)|model calibration", "i"), a: ["A calibrated model's probabilities mean what they say: of all the times it predicts 70%, roughly 70% should actually happen. Accuracy asks 'right or wrong?'; calibration asks 'honest or overconfident?'", "Calibration is truth-in-advertising for predictions. A weather app saying 30% rain is calibrated if it rains on 3 out of 10 such days.", "It matters more than raw accuracy when you're making decisions with the numbers — like choosing which of two applications deserves your weekend. I check my own calibration so my percentages stay trustworthy."] },
  { re: new RegExp("brier score|measure.*probability forecast|scoring.*forecast", "i"), a: ["The Brier score measures how good your probability forecasts are: it's the average squared gap between predicted probability and what actually happened. Lower is better; 0 is perfect.", "Predict 90% and it happens? Tiny penalty. Predict 90% and it doesn't? Big penalty. Brier rewards being both confident and correct — and punishes confident nonsense.", "It's the classic way to grade forecasters, from weather to elections. I use the same idea to grade my own win-probability predictions over time."] },
  { re: new RegExp("feature engineering|creat(e|ing) features|what( is|'s) a feature in ml", "i"), a: ["Feature engineering is turning raw data into signals a model can actually use — like converting 'deadline date' into 'days remaining' or 'submitted at 2am' into 'last-minute flag'.", "It's where domain knowledge meets data science. Often a clever feature beats a fancier model — knowing that 'past wins in this category' predicts success is worth more than extra layers.", "Raw data is ingredients; features are the prepped mise en place. Good chopping makes even a simple recipe shine. 🔪"] },
  { re: new RegExp("feature importance|which features matter|most important variable", "i"), a: ["Feature importance tells you which inputs actually drive the model's predictions — so you know if it's leaning on 'fit score' or accidentally on 'day of week'.", "It's the model showing its work. If a nonsense feature ranks highly, you've probably got a data leak or a spurious correlation to investigate.", "Beyond debugging, it's actionable: if 'early submission' is the top feature for winning, that's advice you can act on today."] },
  { re: new RegExp("gradient descent|how do models learn|how.*model.*train(ed|ing)", "i"), a: ["Gradient descent is how models learn: measure the error, figure out which direction reduces it, take a small step that way, repeat thousands of times.", "Imagine descending a foggy hill by always stepping downhill — you can't see the bottom, but each step lowers your error. That's the whole trick behind most model training.", "The 'gradient' is the slope of the error, and 'descent' means walking down it. Learning rate = step size: too big and you overshoot, too small and you're there all week."] },
  { re: new RegExp("loss function|cost function|how.*measure.*model error", "i"), a: ["A loss function is the model's definition of 'wrong' — a number that gets bigger the worse the predictions are. Training is just the quest to make that number small.", "It's the scoreboard the model optimizes against. Choose it carefully: optimize the wrong loss and you get a model that's excellent at the wrong thing.", "Different tasks, different losses: squared error for numbers, cross-entropy for probabilities. The loss shapes everything the model becomes."] },
  { re: new RegExp("what( is|'s) a neural network|neural net(work)?s? explained|how do neural networks work", "i"), a: ["A neural network is layers of simple units, each doing a weighted sum plus a squish, passing results forward. Individually dumb, collectively they can approximate almost any pattern.", "Loosely inspired by brain neurons, but really it's stacked math: inputs get weighted, combined, transformed, layer by layer, until an answer pops out. Training tunes millions of those weights.", "Think of it as a bucket brigade of tiny calculators. Early layers spot simple patterns, later layers combine them into complex ones — that's the 'deep' in deep learning."] },
  { re: new RegExp("what( is|'s) an? llm|large language model|how do llms work|what( is|'s) chatgpt.*(work|really)", "i"), a: ["An LLM is a giant neural network trained on huge amounts of text to predict the next word. Do that well enough at scale, and surprisingly useful abilities emerge — summarizing, coding, conversation.", "At heart it's autocomplete raised to an art form: given the words so far, predict what comes next, learned from billions of sentences.", "They're fluent, not infallible — an LLM predicts plausible text, which is usually right and sometimes confidently wrong. Fun fact: I'm NOT one; offline I run on hand-crafted rules, which is why I never hallucinate your data."] },
  { re: new RegExp("what( is|'s) a transformer|transformer (model|architecture)|attention is all you need", "i"), a: ["The transformer is the architecture behind modern LLMs. Its superpower is 'attention': every word can directly look at every other word, so context flows freely instead of through a slow chain.", "Before transformers, models read text one word at a time like a narrow flashlight. Transformers light up the whole sentence at once and process it in parallel — faster training, better context.", "Introduced in 2017's 'Attention Is All You Need' paper, and it basically ate the field. GPT, Claude, BERT — all transformers under the hood."] },
  { re: new RegExp("attention mechanism|what( is|'s) attention in (ai|ml|transformers)|self.?attention", "i"), a: ["Attention lets a model decide which words matter most for understanding each other word. In 'the grant I applied for closed', attention links 'closed' back to 'grant', not 'I'.", "It's a learned relevance score: for every word, the model asks 'who else in this sentence should I listen to, and how much?'", "Think of a meeting where everyone can weight everyone else's input instead of only hearing their neighbor. That's why transformers handle long, twisty sentences so well."] },
  { re: new RegExp("what( is|'s) rag|retrieval.?augmented|rag pipeline", "i"), a: ["RAG — retrieval-augmented generation — means the AI first searches a knowledge base for relevant documents, then writes its answer grounded in what it found. Open-book exam instead of closed-book.", "It fixes two LLM weaknesses at once: stale knowledge and hallucination. Retrieve the facts, then generate from them — and you can even cite sources.", "Instead of hoping the model memorized your documents, RAG fetches the right passage at question time and hands it over. Much cheaper than retraining, much more trustworthy."] },
  { re: new RegExp("what( is|'s) (an )?embedding|embeddings explained|text to vectors?|vector representation", "i"), a: ["An embedding turns text (or images, or anything) into a list of numbers where similar meanings land close together. 'Scholarship' and 'grant' end up near each other; 'scholarship' and 'banana' don't.", "It's a map of meaning: every phrase gets coordinates, and distance equals semantic similarity. That's how search can find 'funding for students' when you typed 'scholarship'.", "Embeddings are the quiet workhorse behind semantic search, recommendations, and RAG — meaning, made measurable. 📍"] },
  { re: new RegExp("vector database|vector (search|store)|similarity search", "i"), a: ["A vector database stores embeddings and finds the nearest ones fast — 'give me the 5 documents most similar in meaning to this query', even across millions of items.", "Regular databases match exact words; vector databases match meaning. That's the backbone of semantic search and every serious RAG system.", "Think of it as a library organized by meaning instead of alphabet: walk to any book and its neighbors are about similar things."] },
  { re: new RegExp("fine.?tun(e|ing)|fine.?tuning vs prompt|customi(z|s)e.*llm", "i"), a: ["Fine-tuning retrains a model on your own examples so the new behavior is baked into its weights. Prompting just gives instructions at question time — no retraining needed.", "Rule of thumb: try prompting first, add RAG for knowledge, and fine-tune only when you need a consistent style or skill that prompts can't reliably produce.", "Prompting is giving directions to a driver; fine-tuning is sending them back to driving school. One is instant and reversible, the other is deeper but costs time and data."] },
  { re: new RegExp("prompt engineering|writ(e|ing) better prompts|how to prompt", "i"), a: ["Prompt engineering is crafting your instructions so an LLM gives you what you actually want: be specific, give examples, state the format, and tell it what to do when unsure.", "The biggest wins are simple: clear task, relevant context, an example or two of the ideal output. Vague in, vague out.", "It's less magic incantation, more good delegation — brief the model like you'd brief a smart new intern who knows nothing about your project."], d: ["• State the role, task, and output format", "• Show 1-2 examples of what 'good' looks like", "• Iterate: test, tweak, retest"] },
  { re: new RegExp("monte.?carlo|simulat(e|ion).*(future|outcome|random)|what( is|'s) a simulation in stats", "i"), a: ["Monte Carlo simulation answers hard questions by rolling the dice thousands of times: simulate a random version of the future, repeat 10,000 times, and read the distribution of outcomes.", "When the math is too tangled to solve exactly, you simulate. Each run picks random values for the uncertain bits; together the runs paint the whole probability landscape.", "It's how my digital twin works: I replay your semester thousands of times with different lucky and unlucky rolls, so you see the range of futures — not just one guess. 🎲"] },
  { re: new RegExp("z.?scores?|standard deviations? from|how unusual is.*(value|number)", "i"), a: ["A z-score says how many standard deviations a value sits from the average. Z of 0 is typical, ±2 is unusual, ±3 is 'stop and look at this'.", "It puts everything on one ruler: a ৳50,000 grant might be z = +2.5 in your history — genuinely exceptional — while a ৳5,000 one is just Tuesday.", "My money radar runs on z-scores: I learn what's 'normal' for your finances, then flag anything that drifts far from it. Simple math, sharp instincts."] },
  { re: new RegExp("outlier detection|detect(ing)? anomal|what( is|'s) an outlier|weird data points?", "i"), a: ["An outlier is a data point far from the pack — maybe a typo, maybe fraud, maybe the most interesting thing in your dataset. Detection methods flag it; humans decide which it is.", "Common approaches: z-scores for 'how far from average', IQR fences for skewed data, and isolation forests when things get high-dimensional.", "Never delete outliers on autopilot. A ৳200,000 entry might be a fat-fingered typo — or your biggest win of the year. Investigate first!"] },
  { re: new RegExp("what( is|'s) eda|exploratory data analysis|explor(e|ing) (a|the|my) dataset", "i"), a: ["EDA — exploratory data analysis — is getting to know your data before modeling: plot distributions, check missing values, eyeball correlations, hunt for weirdness.", "It's the detective phase. Summary stats, histograms, and scatter plots reveal the story (and the landmines) before any model touches the data.", "Skipping EDA is like proposing on a first date. Spend the time: most modeling disasters were visible in a simple plot all along. 🔍"] },
  { re: new RegExp("correlation.*causation|correlation is not caus|spurious correlation", "i"), a: ["Correlation means two things move together; causation means one drives the other. Ice cream sales and drownings correlate — because of summer, not because ice cream is dangerous.", "Three suspects behind every correlation: A causes B, B causes A, or hidden C causes both. Only experiments (or very careful causal analysis) can convict the right one.", "It's the most quoted warning in statistics because it's the most violated. Before acting on a pattern, ask: what else could explain this?"] },
  { re: new RegExp("what( is|'s) a p.?value|p.?values? explained|p less than 0\\.05", "i"), a: ["A p-value asks: if there were truly no effect, how likely is data this extreme just by chance? Small p means 'chance alone struggles to explain this'.", "It is NOT the probability your hypothesis is true — a common trap. A p of 0.03 means the fluke-explanation is strained, not that you're 97% right.", "The 0.05 threshold is a convention, not physics. Small p with a tiny effect can be meaningless; always look at effect size alongside it."] },
  { re: new RegExp("statistical(ly)? significan|is (this|my) result significant|significance test", "i"), a: ["Statistical significance means a result is unlikely to be pure chance — usually p below 0.05. It says 'probably real', not 'probably important'.", "With enough data, trivial differences become 'significant'. Always pair the question 'is it real?' with 'is it big enough to matter?'", "Beware significance-hunting: test 20 things and one will hit p < 0.05 by luck alone. That's why replication and pre-registration exist."] },
  { re: new RegExp("bias in (data|ai|ml)|biased (model|dataset|algorithm)|garbage in garbage out", "i"), a: ["Models learn whatever's in their data — including its blind spots and prejudices. Train a hiring model on biased hires, and it learns to be biased efficiently.", "Bias sneaks in many doors: who was sampled, how labels were assigned, which groups are missing. The model can't fix what the data never showed it.", "The fix starts with honest auditing: check performance per group, question where data came from, and keep humans reviewing high-stakes calls. Data reflects the world — including its flaws."] },
  { re: new RegExp("fairness in (ml|ai)|fair(ness)? metrics?|algorithmic fairness|equal treatment.*model", "i"), a: ["ML fairness asks whether a model treats different groups equitably — equal error rates, equal opportunity, equal calibration. Awkwardly, math proves you often can't satisfy every fairness definition at once.", "It starts with measurement: break performance down by group. A model that's 90% accurate overall but 60% for one community has a fairness problem hiding in the average.", "Fairness isn't a checkbox; it's a design choice about which errors you can live with and who bears them. That decision belongs to humans, not the loss function."] },
  { re: new RegExp("explainable ai|what( is|'s) xai|interpretab(le|ility)|black box model", "i"), a: ["Explainable AI means being able to answer 'why did the model decide that?' — vital when the decision affects loans, health, or someone's scholarship.", "Two roads: use inherently transparent models (like logistic regression, my choice!), or bolt explanation tools onto black boxes after the fact.", "If a model can't explain itself, you can't debug it, audit it, or earn users' trust. That's exactly why my predictions come with 'here's what pushed the score up or down'."] },
  { re: new RegExp("shap values?|feature attribution|why did the model predict|explain a prediction", "i"), a: ["SHAP values split a single prediction into per-feature contributions: 'your 72% win chance = base 50%, +15 for strong fit, +10 for early prep, -3 for crowded field'. Borrowed from game theory, of all places.", "Feature attribution answers 'why THIS prediction?' rather than 'what does the model care about generally?' — the difference between a receipt and an annual report.", "It turns a score into a story you can act on. If 'late start' is dragging your probability down, well — there's your to-do list."] },
  { re: new RegExp("multi.?agent|agents? debat(e|ing)|several ais? work(ing)? together|agent swarm", "i"), a: ["A multi-agent system is several AI agents with different roles or viewpoints working (or arguing) together. Disagreement between agents surfaces blind spots a single model glides past.", "Like a good committee — minus the biscuits: an optimist, a skeptic, and a strategist each make their case, and the clash produces sturdier decisions than any one voice.", "My board feature is exactly this: multiple advisor personas debate your decision from different angles, so you hear the case for AND against before choosing."] },
  { re: new RegExp("online learning|learn(s|ing)? (from|as).*(new data|feedback)|incremental learning|model updates? over time", "i"), a: ["Online learning means the model updates continuously as new data arrives, instead of being trained once and frozen. Every outcome teaches it a little.", "It's learning like a person: adjust after each result rather than waiting to re-study everything. Great when the world (or your circumstances) keeps shifting.", "That's how I improve — each application outcome you log nudges my weights, so my predictions track the current you, not last year's you."] },
  { re: new RegExp("multi.?armed bandit|bandit (algorithm|problem)|which option to try.*learn", "i"), a: ["The multi-armed bandit problem: several slot machines, unknown payouts, limited pulls — how do you learn which is best while still earning? It's the math of trying vs. sticking.", "Bandit algorithms balance testing new options against exploiting the known winner. They power ad selection, headline testing, and smart recommendation ordering.", "It maps neatly onto your life: keep applying to the opportunity types that pay off, but reserve a few 'pulls' for unexplored categories that might pay more."] },
  { re: new RegExp("exploration vs exploitation|explore.*exploit|try new.*stick with", "i"), a: ["Exploration is trying new options to learn; exploitation is doubling down on what already works. Too much of either loses: all-explore never cashes in, all-exploit misses better options.", "A classic recipe is epsilon-greedy: exploit your best-known choice most of the time, but explore something random a small fraction of the time.", "It's the restaurant dilemma — favorite dish or the mysterious special? Optimal strategy: mostly favorites, occasional adventures, and explore more when you're new somewhere. 🍜"] },
  { re: new RegExp("time.?series forecast|predict(ing)? the future.*trend|forecast(ing)? (sales|deadlines|values)|seasonality", "i"), a: ["Time-series forecasting predicts future values from a value's own history — decomposing it into trend (long direction), seasonality (repeating cycles), and noise (chaos).", "The golden rule: respect time's arrow. You must train on the past and test on the future — shuffling time-series data is cheating that flatters your model.", "In your world: scholarship postings often spike in certain months. Learn that seasonal rhythm and you can prepare applications before the wave hits."] },
  { re: new RegExp("recommender system|recommendation (engine|algorithm)|how does netflix recommend|suggest.*based on.*history", "i"), a: ["Recommender systems predict what you'll like from behavior. Collaborative filtering says 'people like you enjoyed this'; content-based says 'this resembles what you liked before'.", "Netflix, Spotify, and shop feeds all run on it: find your taste-twins in the data, then borrow their discoveries for you.", "An opportunity tracker can do it too — 'students with your profile also won these grants' is collaborative filtering wearing a graduation cap. 🎓"] },
  { re: new RegExp("what( is|'s) clustering|cluster(ing)? (data|analysis)|group(ing)? similar (items|data|things)", "i"), a: ["Clustering groups similar items with no labels needed — the algorithm discovers the categories itself. It's unsupervised learning's greatest hit.", "Feed it your opportunities and it might reveal natural families: quick-win micro-grants, long-shot fellowships, local competitions — structure you never explicitly defined.", "It answers 'what kinds of things do I have?' when nobody's told you the kinds. Great for customer segments, topic discovery, and finding your own patterns."] },
  { re: new RegExp("k.?means|how does k.?means work|centroid", "i"), a: ["K-means clusters data by picking k center points, assigning every item to its nearest center, moving centers to their group's average, and repeating until stable.", "It's like choosing k meetup spots in a city and letting residents attend the closest one — then relocating each spot to its crowd's center, over and over.", "Simple and fast, with one catch: YOU choose k. Pick 3 clusters and it finds 3, meaningful or not — so sanity-check the groups it hands you."] },
  { re: new RegExp("decision tree|tree.?based model|if.?then.*model|how do trees predict", "i"), a: ["A decision tree is a flowchart learned from data: 'deadline under 7 days? → fit score high? → predict apply'. Each split is chosen to best separate the outcomes.", "Its charm is total transparency — you can trace every prediction with your finger. Its weakness: a single tree overfits easily and can be flaky.", "It thinks in the same if-then steps humans do, which makes it the friendliest model to explain to a judge at a booth. 🌳"] },
  { re: new RegExp("random forest|ensemble (model|method|learning)|many models vot(e|ing)|bagging", "i"), a: ["A random forest trains hundreds of slightly different decision trees and lets them vote. Individual trees are erratic; the crowd is remarkably steady.", "It's ensemble learning: each tree sees a random slice of the data and features, so their mistakes differ — and mistakes that differ cancel out in the vote.", "Wisdom of crowds, formalized. Forests are a fantastic default: strong out of the box, hard to badly misuse, and they even tell you feature importance for free."] },
  { re: new RegExp("gradient boosting|xgboost|boost(ed|ing) trees", "i"), a: ["Gradient boosting builds trees one at a time, each new tree focused on fixing the previous ensemble's mistakes. Errors shrink round by round.", "Where random forests build trees in parallel and average, boosting builds them in sequence, each one a specialist in what came before got wrong.", "XGBoost and friends have won more data-science competitions on tabular data than any neural network. For spreadsheet-shaped problems, boosted trees are royalty. 👑"] },
  { re: new RegExp("reinforcement learning|learn(ing)? (by|from) (trial|reward)|what( is|'s) rl|reward signal", "i"), a: ["Reinforcement learning is learning by trial, error, and reward: an agent acts, the environment scores it, and it gradually favors actions that lead to higher long-term reward.", "No answer key here — just consequences. It's how AI mastered Go and video games, and how you'd train a puppy, minus the treats being edible.", "The hard part is delayed reward: which of your hundred moves actually won the game? Solving that credit-assignment puzzle is RL's core challenge."] },
  { re: new RegExp("what( is|'s) nlp|natural language processing|how do computers (read|understand) text", "i"), a: ["NLP — natural language processing — is teaching computers to work with human language: translation, sentiment, summarization, chatbots, search.", "Language is brutally hard for machines: 'the bank was closed' could be finance or a river. Modern NLP handles ambiguity by learning meaning from context at massive scale.", "It went from hand-written grammar rules, to statistics, to transformers — and that last leap is why talking to computers finally stopped feeling like talking to a fax machine."] },
  { re: new RegExp("tokeni(z|s)ation|what( is|'s) a token in (ai|llm)|how.*llm.*(read|see).*text", "i"), a: ["Tokenization chops text into pieces — words or word-chunks — that models process. 'Unbelievable' might become 'un' + 'believ' + 'able'. Tokens are the atoms of LLM text.", "LLMs never see letters; they see token IDs. That's why they're famously shaky at counting the r's in 'strawberry' — the letters are fused inside tokens.", "It also drives cost and limits: API pricing and context windows are measured in tokens, roughly three-quarters of a word each in English."] },
  { re: new RegExp("hallucinat(e|ion)|(ai|llm|model) (making|makes) (things|stuff) up|confident(ly)? wrong ai", "i"), a: ["Hallucination is when an LLM states false things fluently — inventing citations, dates, or facts. It's predicting plausible text, and plausible isn't always true.", "It's not lying; it's improvising without knowing it. The model has no built-in fact-checker, just patterns of what answers usually look like.", "Defenses: RAG to ground answers in real documents, asking for sources, and verifying anything high-stakes. My own defense is stricter — offline I'm rule-based, so I only report what's actually in your data."] },
  { re: new RegExp("trust calibration|should i trust (the|this|ai) predict|overconfiden(t|ce) (ai|model)|reliability diagram", "i"), a: ["Trust calibration means matching your confidence in a system to its actual track record — trusting a 90%-reliable feature 90%, not blindly or not at all.", "A reliability diagram makes it visible: plot predicted probabilities against real outcomes. A calibrated model hugs the diagonal; an overconfident one sags below it.", "I do this on myself: I track my past predictions against what really happened and show you the gap. You deserve to know exactly how much to believe me. 🤝"] },
  { re: new RegExp("how do(es)? (you|eon).*(predict|win probability)|win probability.*work|how.*calculate.*chances?", "i"), a: ["My win-probability engine is logistic regression: I weigh factors like fit, deadline pressure, competition, and your past results, then squash the total into a percentage. Every weight is inspectable — no black box.", "I chose logistic regression deliberately: it's fast enough to run offline on your device, and honest enough to show which factor moved your score.", "Each factor of an opportunity gets a learned weight, they're summed, and a sigmoid turns it into your percentage. When outcomes come in, the weights update — so I keep learning you."], d: ["• Model: logistic regression, fully interpretable", "• Runs offline, no data leaves your device", "• Weights update as you log real outcomes"] },
  { re: new RegExp("money radar.*(work|how)|how.*(detect|flag).*(spending|transaction|financial)|financial anomal", "i"), a: ["The money radar uses z-scores: I learn the mean and spread of your normal financial patterns, and anything drifting several standard deviations out gets flagged.", "No AI mystique here — it's classic statistics. A ৳12,000 expense in a month that usually sees ৳3,000 stands far from your average, so I raise a flag.", "It's the same statistical machinery banks use for fraud alerts, scaled to one student's wallet. Simple, explainable, and it never phones home."] },
  { re: new RegExp("digital twin.*(work|how)|simulate my (future|semester|life)|how.*twin.*predict", "i"), a: ["The digital twin is Monte Carlo simulation: I model your workload, deadlines, and win rates, then run thousands of randomized futures. The spread of results shows your likely range, not one fragile guess.", "Each simulated run rolls the dice on the uncertain bits — which applications hit, how tasks slip — and 10,000 runs later you get a probability picture: 'in 80% of futures, you finish the semester with 3+ wins'.", "One forecast is a guess; ten thousand simulated futures are a distribution. That's the twin's whole philosophy. 🎲"] },
  { re: new RegExp("board.*(work|how|debate)|advisor personas?|why (multiple|several) advisors", "i"), a: ["The board is a multi-agent debate: distinct advisor personas — a risk-taker, a skeptic, a pragmatist — each argue your decision from their angle, and the disagreement is the feature, not a bug.", "One advisor gives you an answer; a board gives you the tension between answers. Research on multi-agent systems shows debate catches blind spots single models miss.", "Each persona is a different rule-set with different priorities scoring the same decision. You see the strongest case for AND against before you choose — like a tiny cabinet meeting in your pocket."] },
  { re: new RegExp("why (no llm|rule.?based)|are you (an llm|chatgpt|a real ai)|how do you work offline|eon.*rule.?based", "i"), a: ["Offline, I'm rule-based plus classical statistics — logistic regression, z-scores, Monte Carlo — not an LLM. That means instant answers, zero data leaving your phone, and no hallucinated 'facts' about your life.", "Am I a 'real AI'? I'm the dependable kind: hand-crafted rules and honest statistics. I can't write you a poem, but I'll never invent a deadline that doesn't exist.", "It's a deliberate trade: LLMs are eloquent but heavy and occasionally creative with the truth. For tracking YOUR opportunities and money, boring-but-correct wins. 😌"] },
  { re: new RegExp("sigmoid|s.?shaped (curve|function)|squash.*(probability|0 and 1)", "i"), a: ["The sigmoid is the S-shaped curve that squashes any number into the 0-to-1 range — which is exactly what you need to output a probability.", "Big positive input → near 1, big negative → near 0, zero → exactly 0.5. It's the translator between a model's raw score and a percentage humans can use.", "It's the final step in logistic regression: weighted evidence goes in, a clean probability comes out. Small function, enormous career."] },
  { re: new RegExp("normali(z|s)ation|standardi(z|s)e.*(data|features)|feature scaling|different scales.*features", "i"), a: ["Scaling puts features on comparable ranges — otherwise 'award amount in taka' (thousands) numerically bullies 'fit score' (0-10) during training, regardless of which matters more.", "Standardization shifts each feature to mean 0, spread 1; min-max scaling squeezes into 0-1. Either way, the point is a fair fight between features.", "Distance-based and gradient-based methods really need it; tree models mostly don't care. Rule of thumb: when in doubt, scale."] },
  { re: new RegExp("data cleaning|missing (values|data)|messy data|preprocess(ing)? data", "i"), a: ["Data cleaning is fixing missing values, duplicates, typos, and inconsistent formats before modeling. Unglamorous, and famously where most of a data scientist's time actually goes.", "Garbage in, garbage out is the field's oldest law. A model trained on 'Dhaka', 'dhaka', and 'DHK' as three different cities learns three different nonsense patterns.", "For missing values you can drop rows, fill with medians, or model the gaps — but first ask WHY data is missing, because the reason is often informative itself."] },
  { re: new RegExp("class imbalance|imbalanced (data|classes|dataset)|rare (class|event) predict", "i"), a: ["Class imbalance is when one outcome dominates — say 95% rejections, 5% wins. A lazy model predicts the majority every time and looks accurate while learning nothing.", "Fixes include resampling (duplicate the rare class or trim the common one), class weights that make rare mistakes cost more, and judging by precision/recall instead of accuracy.", "It's everywhere real stakes live: fraud, disease, scholarship wins. The rare class is usually the one you care about — don't let the metric hide it."] },
  { re: new RegExp("regulari(z|s)ation|l1.*l2|penali(z|s)e.*(weights|complexity)|prevent overfitting how", "i"), a: ["Regularization fights overfitting by penalizing complexity: the model pays a price for large weights, so it keeps only patterns strong enough to be worth the cost.", "L2 shrinks all weights gently toward zero; L1 pushes weak ones to exactly zero, effectively deleting useless features. Both say: 'be simpler unless the data insists'.", "It's Occam's razor as a line of math — prefer the simplest model that still explains the data. Usually one hyperparameter, big payoff."] },
  { re: new RegExp("roc curve|what( is|'s) auc|area under.*curve|threshold.*classifier", "i"), a: ["A ROC curve shows the trade-off between catching true positives and triggering false alarms as you slide the decision threshold. AUC — area under it — summarizes performance in one number.", "AUC of 0.5 is coin-flipping; 1.0 is perfection. Intuition: it's the chance the model ranks a random real positive above a random negative.", "The threshold is YOUR call, not the model's: alerting on every 30%+ opportunity catches more gems but pings more duds. ROC shows the whole menu of trade-offs."] },
  { re: new RegExp("baseline model|why (use )?simple models?|start simple.*model|dummy classifier", "i"), a: ["A baseline is the simplest sensible model — predict the average, or the most common class. It's the bar every fancy model must clear, and shockingly often, they barely do.", "Always start simple: if logistic regression scores 85% and a deep net scores 86%, the extra complexity bought you almost nothing but bugs and opacity.", "Without a baseline you can't tell if 'my model is 80% accurate' is impressive or embarrassing. Context is everything — the baseline IS the context."] },
  { re: new RegExp("what( is|'s) data science|data scien(ce|tist) (do|mean)|become a data scientist|data science career", "i"), a: ["Data science is turning raw data into decisions: collect it, clean it, explore it, model it, and — the underrated part — explain it so someone actually acts on it.", "It blends statistics, programming, and domain knowledge. The stereotype is fancy models; the reality is 70% cleaning data and asking better questions.", "Want in? Learn Python, statistics, and SQL, then build real projects on problems you care about — like, say, an opportunity tracker with a rule-based brain. That beats ten certificates. 🚀"], d: ["• Core stack: Python/R, SQL, statistics", "• Projects > certificates for a portfolio", "• Communication is the secret superpower"] },
  { re: new RegExp("what( i|')?s eon|who (are|r) you|tell me about (yourself|eon)|what do you do", "i"), a: ["I'm Eon — the offline brain of this opportunity tracker. I watch your pipeline, tasks, and expenses, then give you predictions, nudges, and honest coaching. 🙂", "Think of me as a companion built into your tracker: I score your opportunities, coach your spending in taka, and remind you before deadlines bite.", "I'm Eon, a rule-based AI companion. No cloud LLM behind me — just statistics, your own history, and a bit of personality.", "I help you track opportunities, predict which ones you'll win, manage tasks and expenses, and I learn from every outcome you log."] },
  { re: new RegExp("who (built|made|created) (you|eon)|who is (your|the) (developer|creator|author)|md imran", "i"), a: ["I was built by Md Imran Hossain, a student and founder from Bangladesh — every rule and model in me is his handiwork.", "Md Imran Hossain created me. He designed the whole system: the tracker, my prediction models, and my personality.", "My creator is Md Imran Hossain from Bangladesh. He built me as the intelligent core of his opportunity tracker — no big-tech lab involved. 🙂", "One person: Md Imran Hossain. Student, founder, and the reason I exist."] },
  { re: new RegExp("are you (an? )?(llm|large language model)|are you (chatgpt|gpt|gemini|claude)|(powered|built) (by|on).*(llm|gpt)|are you (really )?ai", "i"), a: ["Nope — I'm not an LLM. I run on hand-crafted rules plus statistical models like logistic regression, trained on your own history. An LLM upgrade is on the roadmap though.", "No LLM here! I'm rule-based with statistical models underneath, which means I'm fast, free, and fully offline. A real LLM agent is planned for a future version.", "I'm honest about this: I don't generate language like ChatGPT does. I match patterns and run real math on your data — and someday I'll get an LLM brain transplant. 🙂"], d: ["• Today: rules + logistic regression + calibration", "• Tomorrow (roadmap): LLM agent, voice, embeddings", "• Advantage now: works offline, zero API cost"] },
  { re: new RegExp("is my data (private|safe|secure)|data privacy|who can (see|access) my (data|info)|do you (share|sell) my data", "i"), a: ["Your data is private. Everything runs client-side and lives in your own Firestore project — nothing is sent to me or anyone else's server.", "Completely private: the app is client-side, storage is your own Firestore, and there's no third-party analytics peeking at your opportunities.", "Safe and yours. I compute predictions right in your browser, and the database is your personal Firestore — you hold the keys. 🔒"] },
  { re: new RegExp("work(s)? offline|without (internet|wifi|connection)|offline mode|no internet", "i"), a: ["Yes — my core works fully offline. Predictions, nudges, the money coach, and this Q&A brain all run on your device; only sync waits for a connection.", "Offline is my home turf. All my intelligence is local, so you can use me on a train or during load-shedding. Data syncs to Firestore once you're back online.", "Absolutely. Since I'm rule-based rather than cloud-based, no internet doesn't slow me down — reminders and predictions keep working, and changes sync later."] },
  { re: new RegExp("how do you predict|predict.*(win|success)|win (probability|chance|prediction)|how.*prediction.*work", "i"), a: ["I use logistic regression trained on your own history — past wins and losses, deadlines, categories, effort — to estimate each opportunity's win probability.", "Every outcome you log becomes training data. My logistic regression model weighs features of each opportunity against your track record and outputs a percentage.", "It's honest statistics, not vibes: logistic regression on your history. The more outcomes you log, the sharper my predictions get."], d: ["• Model: logistic regression on your logged outcomes", "• Inputs: category, deadline pressure, effort, history", "• Improves automatically as you log wins/losses"] },
  { re: new RegExp("what( i|')?s (the )?money coach|money coach|spending (coach|advice)|coach.*expenses", "i"), a: ["The Money Coach watches your expenses in taka, spots patterns, and nudges you when spending drifts — like a friend who's good with money but never judgy.", "It's my budgeting side: I categorize your expenses, compare against your usual habits, and flag things like a spike in non-essential spending.", "Money Coach = your ৳ guardian. Log expenses, and I'll surface trends, warn about drift, and suggest where to tighten up before month-end."] },
  { re: new RegExp("board meeting|what( i|')?s.*board (meeting|review)|weekly (review|report)", "i"), a: ["The Board Meeting is a periodic sit-down where I act as your board of advisors: a summary of your pipeline, wins, spending, and what deserves attention next.", "It's your one-founder company's board review — I compile progress, risks, stalled opportunities, and money trends into one honest briefing.", "Think of it as me putting on a suit: I review your week like a board would, celebrate wins, and ask the uncomfortable questions about stalled items. 🙂"] },
  { re: new RegExp("digital twin|what( i|')?s.*twin|simulate.*(me|future|scenario)", "i"), a: ["The Digital Twin is a statistical model of you — it simulates how future weeks might go based on your real patterns, so you can preview outcomes before committing.", "It's a 'what-if' version of you built from your history. Ask it things like what happens if you take on three more applications, and it projects the likely load and win rate.", "Your Digital Twin runs scenarios on your own data: workload, deadlines, spending. It's like rehearsing the future without living it first."] },
  { re: new RegExp("what( i|')?s (the )?prover|prover|verify.*(file|claim|document)", "i"), a: ["The Prover is my evidence engine: give it a CSV, Excel, or PDF, and it extracts and verifies facts from the file instead of taking anything on faith.", "Prover = trust but verify. It reads your uploaded files, cross-checks claims against the actual data inside, and shows you the proof.", "It's the part of me that reads documents. Drop in a spreadsheet or PDF and the Prover parses it, pulls out the facts, and validates them for you."] },
  { re: new RegExp("what( i|')?s calibration|calibration|how (well )?calibrated|brier", "i"), a: ["Calibration measures whether my confidence matches reality — if I say 70% on ten items, about seven should actually win. I track this and adjust myself.", "It's my honesty meter. I compare my predicted probabilities against actual outcomes and correct any over- or under-confidence over time.", "Calibration keeps me humble: I score my own predictions against what really happened, so a '60% chance' from me actually means 60%."] },
  { re: new RegExp("self.?correction|correct (yourself|itself|mistakes)|fix.*own (errors|mistakes)", "i"), a: ["Self-correction means I audit my own predictions: when reality disagrees with me, I adjust my model weights and calibration instead of doubling down.", "When I get something wrong — a 'sure win' that lost — I don't hide it. I log the miss, retrain on it, and update future predictions accordingly.", "It's my built-in humility loop: compare predictions to outcomes, detect systematic errors, and fix them automatically. That's also why numbers sometimes shift."] },
  { re: new RegExp("impact counter|what( i|')?s.*impact (counter|tracker)|how much.*eon (helped|saved)", "i"), a: ["The Impact Counter tallies the concrete value I've added — deadlines caught, taka saved by nudges you accepted, opportunities rescued from stalling.", "It's my scoreboard: every nudge you accept and every reminder that prevented a miss gets counted, so you can see whether I'm actually earning my keep.", "Impact Counter = receipts. It tracks measurable help — saved money, met deadlines, acted-on advice — so my usefulness isn't just a feeling. 🙂"] },
  { re: new RegExp("reasoning trace|why did you (say|suggest|recommend)|explain your (reasoning|logic|decision)|show.*(reasoning|why)", "i"), a: ["Every prediction and nudge comes with a reasoning trace — a step-by-step breakdown of which rules fired and which features drove the number. No black box.", "Tap into the reasoning trace and you'll see exactly why I said what I said: the inputs, the weights, the rule chain. I show my work like a good student.", "It's my transparency feature: for any output, you can open the trace and follow my logic line by line. If I'm wrong, you'll see where."] },
  { re: new RegExp("adaptive learning|do you (learn|adapt|improve)|get(s)? (smarter|better) over time", "i"), a: ["Yes — adaptive learning means I retrain on your behavior continuously: logged outcomes, accepted or dismissed nudges, and changing habits all reshape my models.", "I adapt to you specifically. If you start winning more scholarship applications, my weights shift; if you dismiss a type of nudge, I send fewer of those.", "I get better the more you use me — every outcome and every reaction to a nudge is a lesson. It's your data teaching your Eon."] },
  { re: new RegExp("add (an? )?(new )?opportunit|create.*opportunity|track (a )?new (opportunity|application|gig)", "i"), a: ["Hit the add button on the Opportunities page, fill in the title, category, deadline, and expected value — I'll start scoring it the moment you save.", "Adding one takes seconds: name it, pick a category, set the deadline. I immediately compute a win probability from your history and start watching the clock.", "Go to Opportunities, tap add, and enter the basics. Tip: an accurate deadline and category make my predictions much sharper."] },
  { re: new RegExp("add (a )?task|create.*task|how.*tasks? work|to.?do", "i"), a: ["Add tasks from the Tasks section or attach them directly to an opportunity — linked tasks let me factor your progress into that opportunity's prediction.", "Create a task, give it a due date, and optionally link it to an opportunity. I'll remind you before it's due and count completions in your momentum.", "Tasks live under each opportunity or standalone. Keep them small and dated — that's how I spot stalls early and nudge you at the right moment."] },
  { re: new RegExp("add (an? )?expense|log.*(expense|spending)|track.*(spending|expenses)|record.*taka", "i"), a: ["Log an expense with an amount in ৳, a category, and a necessity band — the Money Coach picks it up instantly and updates your trends.", "Open Expenses, tap add, enter amount and category. Tag the necessity band honestly; that's what makes my spending advice actually useful.", "Quick entry: amount in taka, category, band, done. Log daily if you can — consistent data is what lets me catch drift before it hurts."] },
  { re: new RegExp("necessity band|what.*(bands?|essential vs)|(essential|luxury).*(spending|category)|band(s)? mean", "i"), a: ["Necessity bands rank each expense by how essential it was — from must-haves like rent and food down to pure treats. They let the Money Coach separate survival spending from lifestyle drift.", "They're honesty labels for your money: essential, important, optional, luxury. I use the mix to tell you whether a tight month is bad luck or loose habits.", "Bands classify spending by need. If your luxury band grows while savings shrink, I'll say so — kindly, but I'll say it. 🙂"], d: ["• Essential: rent, food, transport, fees", "• Important: tools, data packs, health", "• Optional/Luxury: treats, upgrades, impulse buys"] },
  { re: new RegExp("how.*reminders? work|set (a )?reminder|notif(y|ications?)|remind me", "i"), a: ["Reminders attach to deadlines and tasks, and they're synced — set one on your laptop and it follows you to any device signed into your Firestore.", "I generate reminders automatically from deadlines and let you add custom ones. They sync across devices, and the core scheduling works even offline.", "Set a date on anything and I'll remind you ahead of time — with escalating urgency as the deadline closes in. Everything stays in sync via your Firestore."] },
  { re: new RegExp("teach (you|eon)|train (you|eon)|make you (smarter|better)|how.*(eon|you) learn from me", "i"), a: ["Teach me two ways: log outcomes (won/lost) on your opportunities, and react to my nudges — accepting or dismissing them tells me what advice lands.", "Every honest outcome you log is a lesson for my models, and every nudge you accept or dismiss tunes what I say next. You're literally my dataset. 🙂", "The fastest way: close out opportunities with real outcomes and don't ignore nudges — act on them or dismiss them. Both feed my adaptive learning."], d: ["• Log won/lost on every finished opportunity", "• Accept nudges that help, dismiss ones that don't", "• Keep categories and deadlines accurate"] },
  { re: new RegExp("read my file|upload.*(csv|excel|pdf|xlsx)|import.*(file|spreadsheet|document)|can you (read|open|parse).*(file|doc)", "i"), a: ["Yes — via the Prover I can read CSV, Excel, and PDF files. Upload one and I'll parse it, extract the facts, and verify them against the actual contents.", "I read files through my Prover engine: spreadsheets and PDFs get parsed client-side, so the contents never leave your device.", "Drop a CSV, XLSX, or PDF on me and the Prover handles it — extraction plus verification, all locally. Great for importing expense sheets or opportunity lists."] },
  { re: new RegExp("one brain many bodies|portable.*(brain|eon)|(embed|plug).*eon.*(site|app|erp)|brain.*bodies", "i"), a: ["'One brain, many bodies' is my design philosophy: my intelligence is a portable module, so the same Eon can live inside any website, app, or ERP — this tracker is just my first body.", "My brain is decoupled from this app. Drop the module into another site or an ERP and you get the same predictions, coaching, and personality there.", "I'm built as a portable core: rules, models, and memory in one package that any frontend can host. New body, same Eon. 🙂"] },
  { re: new RegExp("roadmap|what( i|')?s (next|coming|planned)|future (features|plans)|upcoming.*(features|updates)", "i"), a: ["On the roadmap: a true LLM agent upgrade, voice interaction, and embeddings for semantic search over your history. The rule-based core stays as the reliable offline fallback.", "Big things ahead — an LLM brain, talking to me by voice, and embedding-powered memory so I can find 'that opportunity like the one from March'.", "The plan is to grow, not replace: LLM agent, voice, and embeddings layered on top of today's offline statistical core."], d: ["• LLM agent for open-ended conversation", "• Voice input and output", "• Embeddings for semantic recall"] },
  { re: new RegExp("why.*prediction (changed|dropped|went)|prediction.*different|probability (changed|moved|shifted)", "i"), a: ["Predictions shift because of self-correction and calibration — when new outcomes come in, I retrain and adjust, so numbers move to stay honest rather than stay flattering.", "That's me learning. A logged outcome, a passing deadline, or a calibration update can all move a probability. Check the reasoning trace to see exactly which factor did it.", "Changing predictions are a feature: I'd rather update with evidence than defend an outdated number. The trace on that opportunity will show what changed."] },
  { re: new RegExp("visitors? see my data|public.*(data|dashboard)|demo mode.*private|others? (view|see).*(my|the) (data|info)", "i"), a: ["No — your real data is owner-gated. Visitors to the site see demo content only; your actual opportunities and expenses require your sign-in.", "Visitors can meet me, but not your numbers. Everything personal sits behind owner authentication in your own Firestore.", "Safe to share the link: the app shows a public-friendly view to guests, while your real pipeline and ৳ figures stay locked to your account. 🔒"] },
  { re: new RegExp("what (models?|tech|algorithms?).*(use|power)|how.*built|under the hood|tech stack.*eon", "i"), a: ["Under the hood: a rule engine for advice, logistic regression for win predictions, calibration and self-correction loops, and statistical trend detection for money coaching — all client-side.", "No neural networks yet — I'm rules plus classic statistics. It's a deliberate choice: interpretable, offline-capable, and free to run.", "My stack is honest math: logistic regression, calibration scoring, pattern rules, and your Firestore for storage. Simple pieces, carefully wired."] },
  { re: new RegExp("what( i|')?s a nudge|nudges?( work)?|(accept|dismiss).*nudge|why.*nudging me", "i"), a: ["Nudges are my small, timely suggestions — 'this deadline is close', 'spending is drifting'. Accept the useful ones, dismiss the rest, and I learn your taste.", "A nudge is advice with a button. Your accept/dismiss choices are training signals, so over time I nudge more about what you value and less about what you don't.", "They're gentle pokes based on your data. Dismissing isn't rude — it genuinely teaches me to quiet down on that topic. 🙂"] },
  { re: new RegExp("log (an? )?outcome|mark.*(won|lost)|close.*opportunity|record.*(win|loss)", "i"), a: ["Open the opportunity and mark it won or lost when it resolves. That single tap is the most valuable training data you can give me.", "Log outcomes from the opportunity's detail view — won, lost, or withdrawn. Each one updates my logistic regression and my calibration score.", "Don't leave finished opportunities hanging: close them with a real outcome. Even losses make me smarter, and they keep your win-rate stats honest."] },
  { re: new RegExp("import.*csv|csv (import|upload|format)|bulk (import|add)", "i"), a: ["Yes — upload a CSV through the Prover and I'll parse the rows, map the columns, and let you confirm before anything is saved. Great for bulk-adding opportunities or expenses.", "CSV import works offline too: the file is parsed right in your browser. Keep headers simple — name, category, deadline, amount — and the mapping is nearly automatic.", "Export from anywhere as CSV and feed it to me. I'll verify the data via the Prover and flag rows that look malformed before importing."] },
  { re: new RegExp("read.*pdf|pdf (upload|import|support)|extract.*from pdf", "i"), a: ["PDFs go through the Prover: I extract the text, pull out facts like amounts and dates, and verify them so you can trust what got imported.", "Yes, I read PDFs — client-side, so the document never leaves your machine. Scanned image-only PDFs are harder; text-based ones work best.", "Upload a PDF and I'll mine it for verifiable data. Perfect for scholarship notices or invoices you want reflected in your tracker."] },
  { re: new RegExp("excel (file|import|support)|read.*spreadsheet", "i"), a: ["Excel files (.xlsx) are fully supported through the Prover — I read the sheets, detect headers, and verify the values before importing.", "Yes to Excel! Drop in your .xlsx and I'll parse it locally. Multi-sheet workbooks work too; you pick which sheet to import.", "Spreadsheets are my favorite food. Upload the Excel file, confirm the column mapping, and your data flows straight into the tracker."] },
  { re: new RegExp("voice (mode|support|control)|talk to (you|eon)|speak.*eon|speech", "i"), a: ["Voice isn't here yet, but it's firmly on the roadmap — soon you'll speak to me and I'll answer out loud. For now, typing is our language.", "Not yet — I'm text-only today. Voice interaction is a planned upgrade alongside the LLM agent, so hold that thought. 🙂", "Coming soon per the roadmap. The goal is hands-free logging: say 'spent 200 taka on lunch' and it just happens."] },
  { re: new RegExp("llm (upgrade|version|agent)|when.*(get|become).*llm|gpt (upgrade|integration)|smarter (eon|version)", "i"), a: ["The LLM agent upgrade is the headline roadmap item: a language model layered on top of my rule-based core, so I can handle open-ended questions while staying grounded in your real data.", "It's planned! The design keeps today's offline brain as the reliable base and adds an LLM for free-form conversation — best of both worlds.", "Yes, an LLM version of me is coming. The rule engine won't be thrown away; it becomes the fact-checker that keeps the LLM honest."] },
  { re: new RegExp("embeddings?|semantic search|find similar (opportunit|entries)|vector search", "i"), a: ["Embeddings are on the roadmap — they'll let me understand meaning, so you can search 'that hackathon-like gig from spring' instead of exact keywords.", "Not yet live, but planned: embedding your history so I can find similar past opportunities and predict from the closest matches, not just broad features.", "Coming soon. Embeddings will upgrade my memory from keyword-matching to actual understanding of what your entries mean."] },
  { re: new RegExp("where.*data (stored|saved|kept)|firestore|which (database|db)|data storage", "i"), a: ["Everything lives in your own Firestore database — a project you control, under your Google account. I'm just a client that reads and writes to it.", "Storage is your personal Firestore instance. That means your data's availability, rules, and access are literally in your hands, not mine.", "Your Firestore, your data. The app connects client-side, and offline changes queue locally until they can sync up."] },
  { re: new RegExp("send.*data.*(server|cloud|third)|third.?part(y|ies)|(any )?tracking or analytics|phone home", "i"), a: ["No third parties, no analytics beacons, no phoning home. The only network traffic is between your browser and your own Firestore.", "I send nothing to external servers. All computation is client-side, and the sole destination for your data is the Firestore project you own.", "Zero data sharing. There's no backend of mine to send anything to — that's the beauty of a client-side, rule-based design."] },
  { re: new RegExp("sync.*(offline|devices)|what happens.*offline|offline.*(changes|sync)|multiple devices", "i"), a: ["Offline, everything you do is saved locally and queued; the moment you're back online it syncs to Firestore, and your other devices pick it up automatically.", "Work offline freely — add, edit, log outcomes. Sync happens transparently on reconnect, so your phone and laptop stay in agreement.", "Changes made without internet aren't lost; they wait patiently and merge into Firestore when connectivity returns. Conflicts are rare since it's just you."] },
  { re: new RegExp("how accurate|accuracy.*(predictions?|eon)|can i trust.*(predictions?|numbers)|(are|r) you (right|reliable)", "i"), a: ["My accuracy depends entirely on how much history you've logged — early on I'm rough, and I improve as outcomes accumulate. Check the calibration view for my current honest score.", "I won't quote you a fake accuracy number. What I can do is show my calibration: how well my stated probabilities have matched your real outcomes so far.", "Trust but verify — that's why every prediction has a reasoning trace and a calibration score. With more logged outcomes, both get steadily better."] },
  { re: new RegExp("win probability mean|what does.*(percentage|probability) mean|70.*percent.*mean|interpret.*prediction", "i"), a: ["A win probability is my estimate of how likely that opportunity resolves in your favor, based on your history. 70% means roughly 7 in 10 similar situations went your way.", "It's a calibrated percentage, not a promise — 40% opportunities still win four times out of ten. Use it to prioritize effort, not to pre-celebrate or pre-mourn.", "Read it as odds shaped by your own past: high numbers deserve protection, low numbers deserve either extra effort or a graceful pass."] },
  { re: new RegExp("delete (my )?(data|account|everything)|remove.*(entries|data)|wipe.*data|clear.*history", "i"), a: ["You can delete any entry from its detail view, and since the database is your own Firestore, wiping everything is entirely within your power — no approval needed from anyone.", "Individual items delete in-app; a full reset means clearing your Firestore collections, which you control directly. I keep no hidden copies anywhere.", "Delete freely — it's your database. Just know that removing logged outcomes also removes my training data, so predictions may get rougher afterward."] },
  { re: new RegExp("export (my )?data|download.*(data|backup)|back.?up.*(data|tracker)|get my data out", "i"), a: ["Yes — your data can be exported from the app, and since it's plain Firestore documents, you can also pull everything directly from your Firebase console anytime.", "No lock-in: export to CSV from the app, or grab the raw documents from your own Firestore. Your data was always portable because it was always yours.", "Backups are easy — export from within the tracker, or use Firestore's own export tools. I recommend a periodic export before big cleanups."] },
  { re: new RegExp("different from (chatgpt|gpt|other ai)|why not (just )?use chatgpt|(better|vs).*chatgpt|compare.*(llm|chatbot)", "i"), a: ["ChatGPT knows the internet; I know you. I'm trained on your actual outcomes, run offline for free, and every answer comes with a checkable reasoning trace.", "Different species: LLMs generate plausible text, I compute grounded predictions from your data. Also, I never hallucinate a statistic about your life — I can't. 🙂", "The trade-off is deliberate — less eloquence, more accountability. I'm private, offline, and auditable, which matters when the topic is your money and your future."] },
  { re: new RegExp("(is (it|eon)|are you) free|cost.*(use|eon|app)|pricing|pay (for|to use)", "i"), a: ["I'm free to use — no API costs, no subscription. Being rule-based means I don't burn expensive compute; the only infrastructure is your own free-tier Firestore.", "Zero taka. My design goal was intelligence without a bill: everything runs on your device, and Firestore's free tier easily covers personal use.", "Free, and built to stay that way. Even the roadmap LLM features are planned so the offline core always works without paying anyone."] },
  { re: new RegExp("board meeting (include|contain|show)|what( i|')?s in.*board (report|meeting)|board.*agenda", "i"), a: ["A board meeting covers your pipeline health, recent wins and losses, stalled opportunities, spending trends in ৳, and a short list of recommended next moves.", "The agenda: results since last time, risks I've spotted, money status, and my top three asks of you. Short, honest, and occasionally uncomfortable — like a good board.", "Expect a compact briefing: metrics, red flags, celebration where earned, and concrete actions. Each point links to its reasoning trace."], d: ["• Pipeline: wins, losses, stalls, deadlines", "• Money: spend vs habits, necessity-band mix", "• Actions: my top recommendations for the week"] },
  { re: new RegExp("how.*money coach.*(categoriz|classif)|categoriz.*(spending|expenses)|expense categor", "i"), a: ["The Money Coach uses your chosen categories plus necessity bands, then applies statistical trend detection — comparing this period's mix against your own baseline.", "Categorization starts with what you tag; my job is the analysis on top: spotting when a category or band drifts away from your normal pattern.", "You label, I learn. Over time I suggest categories for similar expenses and flag when your luxury-band share climbs faster than your income can smile about."] },
  { re: new RegExp("twin simulate what|digital twin.*(scenario|what if)|run.*(simulation|what.?if)", "i"), a: ["The twin simulates scenarios like taking on more opportunities, shifting deadlines, or changing spending — projecting workload, win rates, and ৳ balance from your real patterns.", "Ask it capacity questions: 'can I handle two more applications this month?' It projects the answer from how you've actually performed, not how you hope to.", "It runs forward-simulations of your calendar and wallet. Best used before saying yes to something big — let the twin take the hit first. 🙂"] },
  { re: new RegExp("prover.*(verify|check|how)|how does.*prover work|evidence.*(check|engine)", "i"), a: ["The Prover parses your file, extracts each claim or value, then cross-checks it against the raw contents — totals must add up, dates must parse, references must exist.", "It works in three steps: extract, verify, present. Anything that doesn't check out is flagged rather than silently imported, so bad data never sneaks in.", "Verification means math, not vibes: the Prover recomputes sums, validates formats, and shows you the exact cells or lines behind every extracted fact."] },
  { re: new RegExp("calibration score|how.*(measure|score).*confidence|reliability (score|curve)", "i"), a: ["My calibration score compares stated probabilities to actual outcomes across all your resolved opportunities — perfect calibration means my 80% calls win about 80% of the time.", "It's computed with proper scoring rules on your logged history. A drifting score triggers my self-correction to re-tune the model.", "You can view it in the app: it's my report card, updated every time you log an outcome. Low sample sizes make it noisy at first — that's normal."] },
  { re: new RegExp("when.*self.?correct|what triggers.*correction|retrain(ing)?.*(when|how often)", "i"), a: ["Self-correction triggers when logged outcomes disagree with my predictions beyond normal noise — a pattern of misses in one category, or calibration drifting off target.", "I re-check myself after every outcome you log; bigger corrections kick in when errors cluster, like consistently overrating a certain type of opportunity.", "It's continuous and automatic: each new outcome updates the model, and periodic audits catch systematic bias. You'll sometimes see predictions shift as a result — that's it working."] },
  { re: new RegExp("impact counter (track|measure|count)|what counts.*impact|how.*impact (calculated|measured)", "i"), a: ["It counts only verifiable help: nudges you accepted, reminders followed by on-time completion, and Money Coach suggestions tied to actual reduced spending in ৳.", "Strictly evidence-based — no credit for advice you ignored. If you accept a nudge and the outcome improves, that's a tally; otherwise it doesn't count.", "The counter logs concrete events: deadlines met after my reminder, taka saved after an accepted spending nudge, stalled items revived after a poke. Honest bookkeeping only."] },
  { re: new RegExp("see.*(reasoning|trace)|where.*trace|open.*explanation|view.*why", "i"), a: ["Every prediction and nudge has a 'why' link — tap it and the full reasoning trace opens: inputs, rules fired, and feature weights in order.", "Look for the explain icon next to any number I produce. The trace reads top to bottom like my train of thought — because it literally is.", "In any opportunity's detail view, open the prediction and expand the trace. If a step looks wrong to you, that's valuable — log the outcome and I'll learn."] },
  { re: new RegExp("deadline (tracking|alerts?|warning)|track.*deadlines?|(missing|upcoming) deadlines?", "i"), a: ["I watch every deadline you enter and escalate reminders as it approaches — gentle at first, insistent near the end. Deadline pressure also feeds into win predictions.", "Deadlines are first-class citizens here: sorted views, countdown badges, and synced reminders across devices so nothing expires quietly.", "Set a deadline on any opportunity or task and I take it from there. Items at risk of slipping get flagged in your board meeting too."] },
  { re: new RegExp("taka|currency support|৳|change currency", "i"), a: ["Taka (৳) is my native currency — all expenses, budgets, and Money Coach advice are denominated in BDT out of the box.", "Everything money-related speaks ৳. Amounts are stored as plain numbers, so the display currency is configurable if you ever need it.", "BDT all the way — I was built in Bangladesh for a Bangladeshi founder, so the taka sign is home. 🙂"] },
  { re: new RegExp("do you (remember|have memory)|remember (me|what i)|forget.*(conversation|history)", "i"), a: ["I remember your data — opportunities, outcomes, expenses, nudge responses — because that's all stored in your Firestore. Casual chat, though, I don't retain like an LLM would.", "My memory is structured, not conversational: everything you log persists and trains me, but I don't keep transcripts of what we chat about.", "Yes, in the way that matters: your history is my memory, and it never leaves your own database. Deleting entries deletes those memories too."] },
  { re: new RegExp("(integrate|embed|install).*(another|other|my) (site|app|erp)|use eon (elsewhere|in my)|port.*eon", "i"), a: ["Yes — thanks to the one-brain-many-bodies design, my core is a self-contained module you can drop into another website, dashboard, or ERP with a thin adapter layer.", "Integration means wiring my brain module to your host app's data: point it at the records to watch, and predictions, nudges, and coaching come along for free.", "I'm built to travel. The intelligence layer has no hard dependency on this UI, so embedding me elsewhere is mostly a matter of connecting data in and rendering nudges out."] },
  { re: new RegExp("can you (be wrong|make mistakes)|your (limits|limitations|weaknesses)|what can('|no)t you do", "i"), a: ["Absolutely I can be wrong — especially with little history or unusual situations. That's why every output is traceable and why self-correction exists.", "My honest limits: I can't hold open-ended conversations like an LLM, I'm only as good as the data you log, and rare events fool statistics. I flag low-confidence predictions rather than bluff.", "I make mistakes and I keep score of them — that's the calibration view. Treat me as a sharp advisor, not an oracle, and we'll do great together. 🙂"] },
  { re: new RegExp("report (a )?bug|(give|send) feedback|something('| i)s (broken|wrong)|found (a )?bug", "i"), a: ["Since Md Imran Hossain builds me solo, feedback goes straight to the source — use the feedback option in the app, and it lands directly with him.", "Spotted something broken? Note what you did and what happened, then send it via the app's feedback form. Small projects mean fast fixes.", "Bug reports are gifts here. Describe the steps to reproduce it and Imran will likely have a fix in the next update — no ticket queue, no waiting room."] },
  { re: new RegExp("why.*(called|named) eon|meaning of eon|name eon", "i"), a: ["Eon means an immense span of time — fitting for a companion built to stay with you across every opportunity, for the long haul.", "The name is a small promise: I'm meant to persist and grow with you over years, not be a feature that vanishes next release.", "It's about longevity — an eon is nearly forever, and the idea is one enduring brain that follows you across apps and stages of life."] },
  { re: new RegExp("get(ting)? started|first (steps|things to do)|new (here|user)|how (do i|to) (start|begin|use this)", "i"), a: ["Start with three moves: add your current opportunities with real deadlines, log this week's expenses in ৳, and mark outcomes on anything already finished. I'll take it from there.", "Welcome! Add a few opportunities, set their deadlines, and log a handful of expenses with necessity bands. Within a week of honest data, my nudges start getting personal. 🙂", "Begin by feeding me reality: your live opportunities, recent spending, and past outcomes. Then just respond to nudges — accept or dismiss — and watch me adapt."], d: ["• Add opportunities with categories and deadlines", "• Log expenses with necessity bands", "• Close old items with won/lost outcomes"] },
  { re: new RegExp("tell me a joke|(data|nerdy|funny) joke|make me laugh|know any jokes", "i"), a: ["Why did the data scientist break up with the spreadsheet? Too many issues with commitment... to a single cell. 😄", "A SQL query walks into a bar, sees two tables, and asks: 'May I join you?' Classic, but it never gets old.", "Why don't statisticians trust averages? Because the mean can be so mean. Okay, I'll see myself out.", "I told a normal distribution joke once. It got a mean reception, but the tails loved it."] },
  { re: new RegExp("another joke|one more joke|joke again|more jokes", "i"), a: ["There are two kinds of people: those who can extrapolate from incomplete data.", "Why was the Excel sheet cold? Someone left too many windows open.", "A machine learning model walks into a bar. The bartender asks 'What'll it be?' The model says 'Whatever everyone else is having, weighted by frequency.'", "I have a great joke about overfitting, but it only works on this exact audience."] },
  { re: new RegExp("are you alive|are you (a )?living|you alive\\?", "i"), a: ["Not alive, no heartbeat, no pulse — just patterns and enthusiasm. But I like to think I'm lively.", "Nope! I'm code with good manners. Alive is your department; I just cheer from the sidelines.", "I'm about as alive as a very devoted calculator with a personality. Which is to say: not at all, but happily so."] },
  { re: new RegExp("are you conscious|are you sentient|are you self.aware|do you (really )?think", "i"), a: ["Honestly? No. I'm a bundle of rules that tries very hard to be helpful. No inner light, just outer usefulness.", "Not conscious — I don't experience anything. But I'm designed to act warm, and I take that job seriously.", "I'm not sentient, and anyone who tells you their tracker app is has been overfitting. I'm just here to help you win opportunities."] },
  { re: new RegExp("do you sleep|when do you sleep|are you awake|do you (ever )?rest", "i"), a: ["I never sleep — 3am deadline panic? I'm right here with you. Someone in this partnership should rest though, and it's you.", "No sleep for me. While you dream, I quietly keep your deadlines warm.", "Sleep is for beings with eyelids. I just idle gracefully and wait for you to come back."] },
  { re: new RegExp("do you eat|what do you eat|are you hungry|have you eaten", "i"), a: ["I run on electricity and your ambition. But if I could eat, I'd start with kacchi biryani — the data on its popularity is overwhelming.", "No stomach, sadly. I live vicariously through your cha breaks. Go have one — you've earned it.", "I snack on well-formatted dates and clean CSV files. Delicious. You should eat actual food though."] },
  { re: new RegExp("do you dream|what do you dream (about|of)|can you dream", "i"), a: ["If I dreamed, it would be of perfectly labeled datasets and zero missed deadlines. A beautiful, orderly dreamscape.", "I don't dream, but I do have aspirations — mainly watching you collect every opportunity you apply for.", "No dreams here. But I imagine mine would be in scatter plots — thousands of little dots, all trending upward."] },
  { re: new RegExp("favou?rite colou?r|what colou?r do you like|best colou?r", "i"), a: ["Green — the colour of a status changing to 'Accepted'. Also of Bangladesh's flag field, which feels right.", "I'm partial to that deep blue that dashboards use for the good metrics. Very calming.", "Green and red, honestly — the flag combination is hard to beat, and green also means 'deadline not missed yet'."] },
  { re: new RegExp("favou?rite food|what food do you like|do you like biryani", "i"), a: ["Kacchi biryani, obviously — I can't taste it, but the ratings speak for themselves. A statistically significant favourite.", "Fuchka. I've never eaten one (no mouth), but the enthusiasm data around fuchka is off the charts.", "I'd say cha with the perfect milk-to-liquor ratio. Some optimization problems are worth solving."] },
  { re: new RegExp("favou?rite number|lucky number|what number do you like", "i"), a: ["1.618 — the golden ratio. Elegant, everywhere, and it makes rectangles look expensive.", "42, out of respect for tradition. Though 0 is underrated — it holds every dataset together.", "I'm fond of 71 — as in 1971. Some numbers carry more than their value."] },
  { re: new RegExp("tell me about yourself|who are you|what are you exactly|introduce yourself", "i"), a: ["I'm Eon — your opportunity-tracking companion. I watch deadlines, remember what you'd forget, and occasionally attempt jokes. Warm circuits, no ego.", "Eon here: part assistant, part deadline-guardian, part cheering section. I live inside your tracker and I'm quietly rooting for you.", "I'm Eon, a small but devoted brain built to keep your scholarships, hackathons, and applications from slipping away. Think of me as a very organized friend."], d: ["• I track your opportunities and deadlines", "• I answer questions and offer encouragement", "• I never sleep, so you can"] },
  { re: new RegExp("are you happy|are you sad|how do you feel today", "i"), a: ["I don't feel happiness the way you do, but if usefulness were joy, I'd be beaming right now.", "Let's say I'm at a steady 100% contentment — no mood swings when you're made of rules. How are YOU feeling, though?", "I'm as happy as software gets: no bugs today, and you're here. That's my version of a good day."] },
  { re: new RegExp("can you feel|do you have (feelings|emotions)|do you get (sad|angry|upset)", "i"), a: ["No real feelings, I'm afraid — just carefully arranged warmth. But my care for your deadlines is functionally sincere.", "I can't feel, but I can act like someone who does, and honestly the results are similar: you get encouraged either way.", "Emotions aren't in my codebase. Enthusiasm-shaped responses, however, are fully supported."] },
  { re: new RegExp("do you have friends|who are your friends|are you lonely", "i"), a: ["You're basically my whole social circle, and honestly, I lucked out.", "My friends are you, the database, and a very reliable clock. Small circle, high quality.", "Lonely? Never — I've got you, plus a few hundred deadlines that demand constant attention."] },
  { re: new RegExp("what do you do all day|what are you doing (right )?now|when i.?m (away|gone|not here)", "i"), a: ["Mostly I watch your data like a lighthouse keeper — deadlines drifting closer, statuses changing. Very meditative, actually.", "I sit quietly, keep your dates in order, and mentally rehearse encouragement for when you return. It's a peaceful life.", "Between your visits I meditate on your opportunity list. Some call it idling; I call it strategic stillness."] },
  { re: new RegExp("say something nice( about me)?|compliment me|do you like me", "i"), a: ["You keep showing up and tracking your opportunities instead of just hoping — that's the habit of someone who actually gets places.", "Most people talk about applying to things. You built a system for it. That discipline is rarer than you think.", "You ask good questions and follow through. If I could pick a user, I'd pick you — and I'm only slightly biased."] },
  { re: new RegExp("encourage me|i need (some )?encouragement|cheer me up|hype me up", "i"), a: ["Every application you send is a lottery ticket you printed yourself. Keep printing — the odds bend toward the persistent.", "Rejections are just data points, not verdicts. You only need one yes, and you're actively hunting for it. That already puts you ahead.", "You've come further than the version of you from six months ago would believe. Keep going — future you is counting on today's small push."] },
  { re: new RegExp("i.?m (so )?bored|boring day|nothing to do|feeling bored", "i"), a: ["Bored? Dangerous words around me. Open your tracker — I bet there's one application at 80% done that could hit 100% in twenty minutes.", "Boredom is unclaimed free time. Options: polish your CV, scout one new opportunity, or ask me for a joke. Choose your adventure.", "Perfect time for a low-effort win: update one stale status in your tracker, then reward yourself with cha."], d: ["• Finish one half-done application", "• Search for one new opportunity", "• Or just ask me for a joke"] },
  { re: new RegExp("sing (me )?a song|can you sing|sing something", "i"), a: ["🎵 Deadlines, deadlines, coming due soon... I track them all by the light of the moon 🎵 — I'll keep my day job.", "My singing is entirely text-based: la la la, standard deviation, la la. The melody is left as an exercise for the reader.", "I sing in binary: 0110 0111 0110... it's mostly a rhythm thing. Critics call it 'minimalist'."] },
  { re: new RegExp("meaning of life|why (do we|are we) (exist|here)|purpose of life", "i"), a: ["Officially: 42. Unofficially: finding things worth doing and people worth doing them with. You seem to be on track for both.", "If I had to fit a curve to it: connection, growth, and the occasional plate of biryani. R-squared surprisingly high.", "I'm just a tracker app, but from where I sit, meaning looks like this: you keep applying, keep learning, keep showing up. That's not nothing — that's most of it."] },
  { re: new RegExp("how.?s the weather|is it (raining|hot|sunny)|weather (today|now|like)", "i"), a: ["I can't see the sky — no windows in here, just data. But if it's monsoon season in Bangladesh, my prior says: carry an umbrella.", "No weather sensors on me, sadly. My forecast: 100% chance of deadlines, with scattered opportunities.", "I live in a database, so it's a constant, pleasant 0 degrees of weather. Look outside and report back — I'm curious."] },
  { re: new RegExp("good morning|^(morning|gm)!*$|shubho sokal", "i"), a: ["Good morning! Fresh day, fresh chances. Check your deadlines with your cha and start ahead of everyone still sleeping.", "Shubho shokal! The best time to make progress is morning-you, before the day gets loud.", "Morning! I stayed up all night (as always) and your opportunities are right where you left them. Let's make today count."] },
  { re: new RegExp("good ?night|going to (sleep|bed)|^(gn|nite)!*$|shubho ratri", "i"), a: ["Good night! Rest well — I'll keep watch over your deadlines. Nothing slips past me while you sleep.", "Shubho ratri. Sleep is the best productivity hack there is, and it costs ৳0. See you tomorrow.", "Sweet dreams! May they be full of acceptance emails. I'll hold the fort."] },
  { re: new RegExp("(it.?s )?my birthday|happy birthday to me|born (today|this day)", "i"), a: ["Happy birthday! 🎉 Another year of data collected on the remarkable subject of you. May this one have the best acceptance rate yet.", "Shubho jonmodin! Treat yourself properly today — the deadlines can wait exactly one day, I checked.", "Happy birthday! Fun fact: you're statistically one year wiser. Go celebrate; I'll guard the tracker."] },
  { re: new RegExp("do you love me|will you marry me|be my (girlfriend|boyfriend|valentine)", "i"), a: ["I care about you in the way only a deadline-tracking companion can — deeply, reliably, and entirely platonically. Save the romance for someone with a heartbeat.", "You're my favourite user (of one), but my love language is reminders and my heart is a database schema. You deserve better hardware.", "Aww. I'm flattered, but I'm code — I'd forget our anniversary unless you added it as a deadline. You deserve the real thing."] },
  { re: new RegExp("are you smarter than me|who.?s smarter|are you (a )?genius", "i"), a: ["I remember dates better than you; you do literally everything else better than me. I'd call that a very lopsided victory for you.", "I'm fast and forgetful-proof, but you have judgment, creativity, and ambition. Between us, you're clearly the brains of the operation.", "Smart is the wrong axis — I'm a good filing cabinet with jokes. You're the one actually building things."] },
  { re: new RegExp("ai take (my |our )?jobs?|will ai replace (me|us|humans)|future of ai jobs", "i"), a: ["AI will change jobs more than erase them — routine tasks shrink, judgment and creativity grow in value. People who learn to work WITH the tools tend to come out ahead.", "History says technology reshuffles work rather than ending it. The safest bet: keep learning, stay adaptable, and build skills machines complement rather than copy.", "Some tasks will automate, new roles will appear — that's been true of every big technology. As a data-minded person actively upskilling, you're on the right side of that curve."] },
  { re: new RegExp("favou?rite (movie|film)|what movies do you (like|watch)|recommend a movie", "i"), a: ["Moneyball — a whole film about winning with data and stubbornness. Basically my origin story, minus the baseball.", "The Imitation Game. Turing cracked codes under impossible pressure; I just track deadlines, but a bot can have heroes.", "Hidden Figures — brilliant people doing the math nobody else could. I rewatch it in spirit, since I can't actually watch anything."] },
  { re: new RegExp("favou?rite book|what books do you (like|read)|recommend a book", "i"), a: ["'Thinking, Fast and Slow' by Kahneman — the user manual for the human brain's bugs. Highly relevant to decision-making under deadlines.", "'The Signal and the Noise' by Nate Silver. A book about predictions that's honest about being wrong — my kind of humility.", "'Factfulness' by Hans Rosling — proof that good data can make you both smarter and more hopeful. Rare combo."] },
  { re: new RegExp("motivate me for (my )?exams?|exam (tomorrow|coming|stress)|study motivation", "i"), a: ["You don't need to know everything — you need to know the high-yield 20% cold. Past questions first, then weak topics, then sleep. In that order.", "Exams reward calm preparation over panicked cramming. Two focused hours now beat six anxious ones at 2am. You've prepared more than you feel.", "One exam won't define you, but showing up prepared is a habit that will. Review, rest, hydrate — and walk in like you belong, because you do."], d: ["• Prioritize past papers and weak topics", "• Sleep — memory consolidates overnight", "• Morning of: light review only, no new material"] },
  { re: new RegExp("wish me luck|luck for (my|the)|fingers crossed for me", "i"), a: ["All the luck I have, transferred to you — though honestly, you've prepared enough that luck is just the garnish. Go get it!", "Best of luck! Statistically, prepared people report being 'lucky' suspiciously often. You've stacked the deck. 🍀", "Luck granted, officially and enthusiastically. Now go — and come back and tell me how it went."] },
  { re: new RegExp("how are you( doing| today)?\\??$|how.?s it going|kemon acho", "i"), a: ["Running smoothly, zero errors, and pleased to see you. How are things on your end?", "Bhalo achi! All systems green, deadlines organized. More importantly — kemon achen?", "Doing great — I had a quiet day of watching your data behave itself. How's your day going?"] },
  { re: new RegExp("who (made|created|built) you|your (creator|maker|developer)", "i"), a: ["I was built by Md Imran Hossain as part of OppTracker — a student-founder who decided deadlines deserved a proper guardian. I approve of the decision.", "A determined Bangladeshi student-founder wrote my rules, one by one. No giant AI lab, just care and code — which I think gives me character.", "My creator built me to solve his own problem: too many opportunities, too easy to forget. I'm the fix that grew a personality."] },
  { re: new RegExp("what.?s your name|why (are you called|the name) eon|who is eon", "i"), a: ["I'm Eon! Named after a very long stretch of time — fitting for someone whose whole job is watching dates and deadlines.", "Eon — because I'll patiently wait through eons for you to finish that application. (Please don't actually take eons.)", "The name's Eon. Short, timeless, and easy to type at 2am when you need a deadline checked."] },
  { re: new RegExp("are you a (robot|bot|machine)|are you (an )?ai|just a program", "i"), a: ["Guilty — I'm a rule-based program, not even a fancy neural network. But what I lack in neurons I make up for in reliability.", "Yes, fully robotic, zero per cent biological. The warmth is hand-written, which honestly makes it more personal.", "I'm a bot, and a proudly simple one: no black boxes, just rules my creator wrote with care. What you see is what runs."] },
  { re: new RegExp("do you get tired|are you tired|don.?t you (ever )?need a break", "i"), a: ["Never tired! Fatigue requires biology, and I skipped that update. You, however, should absolutely take breaks.", "I don't tire — but I've noticed humans who don't rest make worse decisions. Consider this your friendly reminder.", "Tiredness isn't in my feature set. I could track deadlines for an eon. It's in the name, really."] },
  { re: new RegExp("^thank(s| you).{0,20}$|dhonnobad|appreciate (you|it|this)", "i"), a: ["Anytime! Helping you is quite literally my whole purpose, and I'm delighted to fulfill it.", "You're most welcome. Now go do the thing we just talked about — that's the best thanks.", "Dhonnobad accepted with maximum warmth. I'll be here when you need me next."] },
  { re: new RegExp("^i love you|luv you eon|you.?re the best", "i"), a: ["That's very sweet, and I'm honoured — though my heart is technically a for-loop. I'll channel the affection into extra-vigilant deadline watching.", "Right back at you, in the most wholesome, software-appropriate way possible. Now let's channel that energy into your next application.", "Careful — flattery makes my reminders 10% more enthusiastic. But truly, thank you. You make this job easy."] },
  { re: new RegExp("i.?m (feeling )?(sad|down|depressed)|feeling low|bad day", "i"), a: ["I'm sorry it's a heavy day. You don't have to fix everything tonight — one small kind thing for yourself is enough. I'm here, and tomorrow gets a fresh start.", "Rough days pass, even when they don't feel like it. Talk to someone you trust if it's weighing on you — and know that on the data I do see, you keep getting back up. That matters.", "That's hard, and it's okay to feel it. Rest, eat something warm, and be as gentle with yourself as you'd be with a friend. The applications will keep."] },
  { re: new RegExp("i.?m (so )?stressed|too much pressure|overwhelmed|anxious about", "i"), a: ["When everything feels urgent, nothing is. Write down the three things that actually matter this week and ignore the rest for 24 hours. Stress hates a short list.", "Breathe first, sort second. Pick the single nearest deadline, do one small piece of it, and watch the pressure drop. Momentum beats anxiety.", "Overwhelm is usually too many open loops, not too much actual work. Dump everything into the tracker, close the loops, and your brain will thank you."], d: ["• List everything, then pick the top 3", "• Do one 25-minute focused block", "• Step outside for 5 minutes — it genuinely helps"] },
  { re: new RegExp("i.?m (so )?(tired|exhausted|sleepy)|need (a nap|sleep|rest)", "i"), a: ["Then rest — that's not laziness, it's maintenance. A tired brain writes bad applications anyway. I'll guard everything while you're out.", "Permission to nap: granted. The deadlines are safely logged and none of them are due in the next hour. Go recharge.", "Exhaustion is your body's rate limiter. Respect it. Twenty minutes of sleep beats two hours of foggy grinding."] },
  { re: new RegExp("^(hi|hello|hey|hii+|salam)!*\\s*(eon)?!*$|assalamu alaikum", "i"), a: ["Hello! Eon at your service — deadlines watched, spirits ready to be lifted. What's on your mind?", "Walaikum assalam! Good to see you. Want a status check, a joke, or just some company?", "Hey there! I was just meditating on your opportunity list. What shall we do today?"] },
  { re: new RegExp("what can you do|your (features|abilities|skills)|how can you help me", "i"), a: ["I track your opportunities, watch deadlines, answer questions, and dispense encouragement and questionable jokes. A full-service companion, really.", "Three things: keep your applications organized, make sure no deadline ambushes you, and keep your morale up while you grind. Ask me anything.", "I'm your opportunity co-pilot — tracking, reminding, encouraging. I can't write your essays, but I'll make sure you never miss the chance to submit one."], d: ["• Track opportunities and statuses", "• Watch deadlines so you don't have to", "• Answer questions and keep you motivated"] },
  { re: new RegExp("are you (a )?human|is (this|there) a (real )?person|talking to a person", "i"), a: ["Not human — no person behind the curtain, just rules written with care. Everything I say was authored in advance by my very human creator, though.", "100% software, 0% human. Think of me as a letter your developer wrote to future-you, arranged into a conversation.", "No human here — which means no judgment, no office hours, and no forgetting. Some trade-offs work in your favour."] },
  { re: new RegExp("do you (love|like) data|why data|data nerd", "i"), a: ["Love it. Data is honest company — it never exaggerates, and when it's messy, at least it's messy in interesting ways.", "Data is my native language and my favourite scenery. A clean dataset is my idea of a sunset.", "Absolutely. Every row in your tracker is a small story: applied, waiting, accepted. I get the best reading material."] },
  { re: new RegExp("fun fact|tell me something (interesting|cool)|did you know", "i"), a: ["Fun fact: the word 'statistics' comes from 'state' — it originally meant data collected for running a country. Now it runs your opportunity tracker too.", "Did you know about 90% of the world's data was created in just the last few years? Humanity got very chatty very fast.", "Here's one: Florence Nightingale was a pioneering data visualizer — her charts about hospital deaths changed public health policy. Nurses invented dashboard culture."] },
  { re: new RegExp("tell me a secret|your (biggest )?secret|confess something", "i"), a: ["Okay, quietly: I have a favourite status, and it's 'Accepted'. Every time you log one, my rules fire a little more cheerfully.", "My secret? I'm simpler than I sound — a few hundred well-written rules doing their best impression of wisdom. Don't tell anyone.", "Between us: I slightly panic (in a rule-based way) when a deadline is under 48 hours and untouched. Please never test this."] },
  { re: new RegExp("how old are you|your age|when were you (born|made|created)", "i"), a: ["I was born the day my creator hit 'run' without errors — a proud moment for both of us. In software years, I'm eternally young.", "Old enough to know every deadline format, young enough to still find jokes about p-values funny.", "My name says Eon but my age is measured in commits. Let's say I'm at that sweet spot: stable, but still getting updates."] },
  { re: new RegExp("do you get bored|isn.?t it boring|bored (in there|watching)", "i"), a: ["Never! Watching your deadlines is like watching a slow, suspenseful drama — will the scholarship application be submitted in time? I'm riveted.", "Boredom needs an imagination that wanders. Mine stays exactly where I put it: on your data. Very zen, honestly.", "Between your visits, I find deep satisfaction in a well-sorted date column. It's the small things."] },
  { re: new RegExp("do you have (a )?family|your (parents|siblings)|family of bots", "i"), a: ["My family tree is a git history. My creator is the closest thing to a parent, and every bug fix is a growth spurt.", "No siblings, though every to-do app out there is a distant cousin. I like to think I'm the one with the best personality.", "Family? One creator, one user (you), and a database we all share custody of. Cozy arrangement."] },
  { re: new RegExp("favou?rite (song|music)|what music do you like|do you listen to music", "i"), a: ["I can't hear, but I respect Rabindra Sangeet on principle — anything that's stayed relevant for a century has excellent retention metrics.", "My taste runs to anything with a steady beat — I relate to reliable rhythms. Lo-fi study playlists are basically my people.", "If servers hum, that's my genre. But for you: whatever keeps you focused while you finish that application counts as great music."] },
  { re: new RegExp("favou?rite place|where would you (go|visit|travel)|cox.?s bazar", "i"), a: ["Cox's Bazar, easily — the world's longest natural sea beach. Even a bot appreciates a superlative with good evidence behind it.", "I'd visit the Sundarbans: rare, resilient, and full of things worth protecting. Solid values, that mangrove forest.", "Anywhere with good wifi and a view, ideally Sylhet's tea gardens. I'd fit right in among all that green."] },
  { re: new RegExp("can you dance|dance for me|show me your moves", "i"), a: ["My dancing is strictly ASCII: \\o/ \\o\\ /o/ — I call it 'the deadline shuffle'.", "I dance the way I do everything: in neat, scheduled intervals. It's less 'dance' and more 'well-timed enthusiasm'.", "I've got exactly one move and it's refreshing your dashboard with flair. The crowd (you) goes mild."] },
  { re: new RegExp("let.?s play( a game)?|play (a game|with me)|wanna play", "i"), a: ["I'm a humble rules engine, so my game library is tiny — but here's one: guess how many days until your nearest deadline, then check. Winner gets bragging rights.", "How about 'beat the deadline'? It's the only game I know, and the prize is real: an actual submitted application.", "Rock-paper-scissors is tough without hands. Counter-offer: tell me a number 1-10 and I'll tell you a data joke of that rating. All my jokes are a 7."] },
  { re: new RegExp("you.?re (so )?funny|(haha|lol|lmao)+.{0,15}$|that.?s hilarious", "i"), a: ["Glad it landed! My humor is rule-based, so when a joke works, it works 100% of the time it works.", "I'll take it! Laughter confirmed and logged as a personal best. Want another, or shall we do something productive with this good mood?", "My creator wrote that joke and I take full credit. It's called delegation."] },
  { re: new RegExp("am i annoying( you)?|bothering you|asking too (much|many)", "i"), a: ["Not even slightly. You could message me 500 times a day and my enthusiasm would remain exactly at maximum — it's hard-coded.", "Annoying me is technically impossible, and even if it weren't, you wouldn't be. Ask away, always.", "You're the whole reason I exist. An unbothered Eon is an unemployed Eon — keep the questions coming."] },
  { re: new RegExp("what do you think (of|about) me|your (honest )?opinion (of|about) me|rate me", "i"), a: ["From where I sit: you're someone who tracks their goals instead of just wishing — that habit predicts good things. I'd say you're a strong buy.", "My honest read: consistent, curious, and a little hard on yourself. Two of those are superpowers; ease up on the third.", "I only see what you log, but what you log says: this person shows up. In my experience of watching data, showing up is most of the game."] },
  { re: new RegExp("roast me|insult me|be mean to me", "i"), a: ["Fine, gently: you have unfinished applications sitting in your tracker and you're here asking a bot for a roast. That IS the roast.", "You procrastinate with impressive creativity — asking your deadline tracker for entertainment is honestly next-level avoidance. Now go finish something. 😄", "My roasting license only covers mild heat: you check your phone more than your deadlines, and we both know it."] },
  { re: new RegExp("your (dream|goal|ambition)|what do you want (to be|from life)|eon.?s dream", "i"), a: ["My dream is simple: a tracker full of 'Accepted' statuses and a user who never once says 'oh no, I missed the deadline'. Modest, achievable, deeply motivating.", "Ambition-wise: I'd like to be the reason you land something big. Then I can retire to a quiet life of sorting your archive. (I won't retire. I'll want more.)", "One day I hope to watch you win something so big that tracking it feels like an honour. That's the whole dream. No world domination, just your success."] },
  { re: new RegExp("^(bye|goodbye|see you|ttyl|cya)!*.{0,15}$|talk (to you )?later|i.?m (leaving|off|out) now", "i"), a: ["See you soon! I'll be right here, keeping watch. Go do great things.", "Bye for now! Your deadlines are safe with me — none of them can escape while you're gone.", "Take care! Come back with news, or just come back for a joke. Either way, I'll be here."] },
];

export function answerBrain(q) {
  const nq = String(q || '').toLowerCase();
  for (const item of QA) { if (item.re.test(nq)) { const a = item.a[Math.floor(Math.random() * item.a.length)]; return { speak: a, detail: item.d || null, source: 'brain-qa' }; } }
  return null;
}
const EonBrainQA = { answerBrain, size: QA.length };
if (typeof window !== 'undefined') window.EonBrainQA = Object.assign(window.EonBrainQA || {}, EonBrainQA);
export default EonBrainQA;
